const WASTE_PICKUP_TYPE_OPTIONS = ["Garbage", "Recycling", "Compost", "Yard waste", "Bulk items"];
type WastePattern = "weekly" | "biweekly_same" | "alternating";

function getWastePickupTypes(value: string | null | undefined) {
  const normalized = (value || "").toLowerCase();
  return WASTE_PICKUP_TYPE_OPTIONS.filter((option) =>
    normalized.includes(option.toLowerCase())
  );
}

function getWastePickupLabel(value: string | null | undefined) {
  const selected = getWastePickupTypes(value);
  return selected.length > 0 ? selected.join(", ") : value || "";
}

function toggleWastePickupType(currentValue: string, option: string) {
  const current = new Set(getWastePickupTypes(currentValue));
  if (current.has(option)) current.delete(option);
  else current.add(option);

  return WASTE_PICKUP_TYPE_OPTIONS.filter((item) => current.has(item)).join(", ");
}

function isNoWastePickupLabel(value: string | null | undefined) {
  return (value || "").trim().toLowerCase() === "no pickup";
}

function inferWastePattern(property: Property | null | undefined): WastePattern {
  if (!property?.garbage_rotation_anchor_date) return "weekly";
  if (isNoWastePickupLabel(property.garbage_week_b_label)) return "biweekly_same";
  return "alternating";
}

function getPropertyColor(propertyId: string | null) {
  if (!propertyId) {
    return { bg: "#f4efe8", text: "#6f6255", border: "#d8c7ab" };
  }

  let hash = 0;
  for (let i = 0; i < propertyId.length; i += 1) {
    hash = (hash * 31 + propertyId.charCodeAt(i)) >>> 0;
  }

  return PROPERTY_CALENDAR_COLORS[hash % PROPERTY_CALENDAR_COLORS.length];
}

function buildPropertyAddress(parts: Array<string | null | undefined>) {
  return parts
    .map((part) => (part || "").trim())
    .filter(Boolean)
    .join(", ");
}

function parseCoordinate(value: string | number | null | undefined) {
  if (value === null || value === undefined || value === "") return null;
  const parsed = typeof value === "number" ? value : Number(String(value).trim());
  return Number.isFinite(parsed) ? parsed : null;
}

function formatDistance(meters: number) {
  if (meters < 1000) return `${Math.round(meters)} m away`;
  return `${(meters / 1000).toFixed(1)} km away`;
}

function getDistanceMeters(
  from: { latitude: number; longitude: number },
  to: { latitude: number; longitude: number }
) {
  const earthRadiusMeters = 6371000;
  const toRadians = (degrees: number) => (degrees * Math.PI) / 180;
  const lat1 = toRadians(from.latitude);
  const lat2 = toRadians(to.latitude);
  const deltaLat = toRadians(to.latitude - from.latitude);
  const deltaLon = toRadians(to.longitude - from.longitude);
  const a =
    Math.sin(deltaLat / 2) ** 2 +
    Math.cos(lat1) * Math.cos(lat2) * Math.sin(deltaLon / 2) ** 2;
  return earthRadiusMeters * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
}

function parseAddressLine(addressLine: string) {
  const parts = addressLine
    .split(",")
    .map((part) => part.trim())
    .filter(Boolean);

  if (parts.length === 0) {
    return { street: "", city: "", province: "", postal: "" };
  }

  const street = parts[0] || "";
  const city = parts[1] || "";
  const regionPostal = parts.slice(2).join(" ").trim();
  const tokens = regionPostal.split(/\s+/).filter(Boolean);

  if (tokens.length <= 1) {
    return {
      street,
      city,
      province: regionPostal,
      postal: "",
    };
  }

  return {
    street,
    city,
    province: tokens[0] || "",
    postal: tokens.slice(1).join(" "),
  };
}

function normalizeIcalUrl(rawValue: string) {
  const trimmed = rawValue.trim();
  if (!trimmed) return "";
  if (trimmed.toLowerCase().startsWith("webcal://")) {
    return `https://${trimmed.slice("webcal://".length)}`;
  }
  return trimmed;
}

function createInviteToken() {
  return typeof crypto !== "undefined" && "randomUUID" in crypto
    ? crypto.randomUUID()
    : `${Date.now()}-${Math.random().toString(36).slice(2)}`;
}

