  function updateDeletionRequestDraft(
    requestId: string,
    field: "status" | "adminNotes",
    value: string
  ) {
    setDeletionRequestDrafts((prev) => ({
      ...prev,
      [requestId]: {
        status: prev[requestId]?.status || "pending",
        adminNotes: prev[requestId]?.adminNotes || "",
        [field]: value,
      },
    }));
  }

  async function saveDeletionRequest(request: AccountDeletionRequestRow) {
    if (!currentOrganizationId) return;

    setSavingDeletionRequestId(request.id);
    setError("");
    setActionMessage("");

    try {
      const draft = deletionRequestDrafts[request.id] || {
        status: request.status,
        adminNotes: request.admin_notes || "",
      };
      const {
        data: { session },
      } = await supabase.auth.getSession();

      if (!session?.access_token) {
        throw new Error("No active admin session was found.");
      }

      const response = await fetch("/api/admin/account-deletion-request", {
        method: "PATCH",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${session.access_token}`,
        },
        body: JSON.stringify({
          requestId: request.id,
          organizationId: currentOrganizationId,
          status: draft.status,
          adminNotes: draft.adminNotes,
        }),
      });
      const payload = await response.json().catch(() => null);

      if (!response.ok || payload?.ok === false || !payload?.request) {
        throw new Error(payload?.error || "Could not update account deletion request.");
      }

      const updatedRequest = payload.request as AccountDeletionRequestRow;
      setAccountDeletionRequests((requests) =>
        requests.map((item) => (item.id === updatedRequest.id ? updatedRequest : item))
      );
      setDeletionRequestDrafts((prev) => ({
        ...prev,
        [updatedRequest.id]: {
          status: updatedRequest.status,
          adminNotes: updatedRequest.admin_notes || "",
        },
      }));
      setActionMessage("Account deletion request updated.");
    } catch (saveError) {
      setError(saveError instanceof Error ? saveError.message : "Could not update account deletion request.");
    } finally {
      setSavingDeletionRequestId(null);
    }
  }

  async function markChatConversationRead(conversationId: string) {
    if (!conversationId || !currentAdminUserId) return;

    const readAt = new Date().toISOString();
    setChatParticipants((participants) =>
      participants.some(
        (participant) =>
          participant.conversation_id === conversationId && participant.participant_profile_id === currentAdminUserId
      )
        ? participants.map((participant) =>
            participant.conversation_id === conversationId && participant.participant_profile_id === currentAdminUserId
              ? { ...participant, last_read_at: readAt }
              : participant
          )
        : [
            ...participants,
            {
              id: `local-admin-read-${conversationId}`,
              organization_id: currentOrganizationId || "",
              conversation_id: conversationId,
              participant_type: "profile",
              participant_profile_id: currentAdminUserId,
              participant_role: "admin",
              display_name: currentAdminProfile?.full_name || currentAdminProfile?.email || "Admin",
              email: currentAdminProfile?.email || null,
              last_read_at: readAt,
              created_at: readAt,
            },
          ]
    );

    const {
      data: { session },
    } = await supabase.auth.getSession();

    if (!session?.access_token) {
      console.warn("Could not mark chat conversation read", "Missing auth token.");
      return;
    }

    const response = await fetch("/api/chat/admin-read", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${session.access_token}`,
      },
      body: JSON.stringify({ conversationId }),
    });
    const payload = await response.json().catch(() => null);

    if (!response.ok || payload?.ok === false) {
      console.warn("Could not mark chat conversation read", payload?.error || response.statusText);
      return;
    }

    if (payload?.participant) {
      const participant = payload.participant as ChatParticipantRow;
      setChatParticipants((participants) =>
        participants.some((row) => row.id === participant.id || row.id === `local-admin-read-${conversationId}`)
          ? participants.map((row) =>
              row.id === participant.id || row.id === `local-admin-read-${conversationId}` ? participant : row
            )
          : [...participants, participant]
      );
    }
  }

  useEffect(() => {
    if (!currentOrganizationId) return;

    const channel = supabase
      .channel(`admin-chat-realtime-${currentOrganizationId}`)
      .on(
        "postgres_changes",
        {
          event: "INSERT",
          schema: "public",
          table: "chat_messages",
          filter: `organization_id=eq.${currentOrganizationId}`,
        },
        (payload) => {
          const incoming = payload.new as ChatMessageRow;
          setChatHiddenItems((current) =>
            current.filter((item) => !(item.conversation_id === incoming.conversation_id && !item.message_id))
          );
          setChatMessages((current) =>
            current.some((message) => message.id === incoming.id) ? current : [...current, incoming]
          );
          setChatConversations((current) =>
            current.map((conversation) =>
              conversation.id === incoming.conversation_id
                ? {
                    ...conversation,
                    last_message_at: incoming.created_at,
                    updated_at: incoming.created_at,
                  }
                : conversation
            )
          );
        }
      )
      .subscribe((status) => {
        setChatRealtimeReady(status === "SUBSCRIBED");
      });

    return () => {
      setChatRealtimeReady(false);
      void supabase.removeChannel(channel);
    };
  }, [currentOrganizationId]);

  useEffect(() => {
    if (activeSection !== "chat") return;
    const conversationId = selectedChatConversationId || chatConversations[0]?.id || "";
    if (!conversationId) return;
    void markChatConversationRead(conversationId);
  }, [activeSection, selectedChatConversationId, chatConversations, chatMessages.length]);

  useEffect(() => {
    if (activeSection !== "chat") return;
    const thread = chatThreadScrollRef.current;
    if (!thread) return;
    thread.scrollTop = thread.scrollHeight;
  }, [activeSection, selectedChatConversationId, chatMessages.length]);

