  async function linkOwnerAccountToProperty(propertyId: string, ownerEmailRaw: string, ownerNameRaw: string) {
    const ownerEmail = ownerEmailRaw.trim().toLowerCase();
    const ownerName = ownerNameRaw.trim();

    if (!ownerEmail) {
      return false;
    }

    const {
      data: { session },
      error: sessionError,
    } = await supabase.auth.getSession();

    if (sessionError || !session?.access_token) {
      throw new Error("No active admin session was found.");
    }

    const response = await fetch("/api/admin/property-owner", {
      method: "POST",
      cache: "no-store",
      headers: {
        Authorization: `Bearer ${session.access_token}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        propertyId,
        ownerEmail,
        ownerName,
      }),
    });

    const result = await response.json().catch(() => null);

    if (!response.ok || !result?.ok) {
      throw new Error(result?.error || "Could not link owner to property.");
    }

    return true;
  }

  function getPropertyWastePayload() {
    const savedAnchorDate =
      propertyWastePattern === "biweekly_same" || propertyWastePattern === "alternating"
        ? propertyGarbageRotationAnchorDate || null
        : null;
    const savedGarbageDay =
      propertyWastePattern === "alternating"
        ? null
        : propertyGarbageDay.trim() || null;
    const savedWeekALabel =
      propertyWastePattern === "alternating"
        ? propertyGarbageWeekALabel.trim() || "Garbage + recycling"
        : propertyGarbageDay.trim() || "Waste pickup";
    const savedWeekBLabel =
      propertyWastePattern === "alternating"
        ? propertyGarbageWeekBLabel.trim() || "Recycling only"
        : "No pickup";

    return {
      garbageDay: savedGarbageDay,
      garbageRotationAnchorDate: savedAnchorDate,
      garbageWeekALabel: savedWeekALabel,
      garbageWeekBLabel: savedWeekBLabel,
    };
  }

  async function createPropertyViaAdminApi(payload: Record<string, any>) {
    if (!currentOrganizationId) {
      throw new Error("Choose an organization before adding a property.");
    }

    const {
      data: { session },
      error: sessionError,
    } = await supabase.auth.getSession();

    if (sessionError || !session?.access_token) {
      throw new Error("No active admin session was found.");
    }

    const response = await fetch("/api/admin/property", {
      method: "POST",
      cache: "no-store",
      headers: {
        Authorization: `Bearer ${session.access_token}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        organizationId: currentOrganizationId,
        ...payload,
      }),
    });

    const result = await response.json().catch(() => null);

    if (!response.ok || !result?.ok) {
      throw new Error(result?.error || "Could not create property.");
    }

    return result;
  }

  async function addProperty() {
    if (!propertyName.trim()) {
      setError("Property name is required.");
      return;
    }

    setError("");
    setActionMessage("");

    const ownerWasProvided = !!propertyOwnerEmail.trim();

    try {
      const created = await createPropertyViaAdminApi({
        name: propertyName.trim(),
        address: buildPropertyAddress([
          propertyStreet,
          propertyCity,
          propertyProvince,
          propertyPostal,
        ]),
        notes: propertyNotes.trim() || null,
        wifiNetwork: propertyWifiNetwork,
        wifiPassword: propertyWifiPassword,
        garbageNotes: propertyGarbageNotes,
        garbagePickupWeekday: propertyGarbagePickupWeekday,
        ...getPropertyWastePayload(),
        defaultCleanerUnitsNeeded: Number(propertyUnitsNeeded),
        cleanerUnitsRequiredStrict: propertyUnitsStrict,
        showTeamStatusToCleaners: propertyShowTeamStatus,
        ownerEmail: propertyOwnerEmail,
        ownerName: propertyOwnerName,
      });

      const geocodeWarning = String(created?.geocodeWarning || "").trim();
      if (geocodeWarning) {
        setError(geocodeWarning);
      }
    } catch (err: any) {
      const message = err?.message || "Could not create property.";
      setError(
        message.includes("wifi_network") || message.includes("garbage_")
          ? `${message} Run supabase/add_property_inspections.sql first.`
          : message
      );
      return;
    }

    resetManualPropertyForm();
    setActionMessage(ownerWasProvided ? "Property added and owner linked." : "Property added.");
    await loadData();
  }

  async function addAirbnbProperty() {
    if (!airbnbImportName.trim()) {
      setError("Airbnb listing name is required.");
      return;
    }

    if (!airbnbImportStreet.trim() || !airbnbImportCity.trim()) {
      setError("Street and city are required before importing from Airbnb.");
      return;
    }

    if (!airbnbImportCalendarUrl.trim()) {
      setError("Airbnb iCal URL is required for the import wizard.");
      return;
    }

    const normalizedCalendarUrl = normalizeIcalUrl(airbnbImportCalendarUrl);
    try {
      const parsedUrl = new URL(normalizedCalendarUrl);
      if (!["http:", "https:"].includes(parsedUrl.protocol)) {
        throw new Error("Unsupported calendar URL.");
      }
    } catch {
      setError("Enter a valid Airbnb iCal export URL. It should start with https:// or webcal://.");
      return;
    }

    setError("");
    setActionMessage("Creating the property, attaching Airbnb iCal, then syncing bookings automatically.");
    setImportingAirbnbProperty(true);

    let insertedPropertyId: string | null = null;

    try {
      const combinedNotes = [
        airbnbImportNotes.trim(),
        airbnbImportListingUrl.trim() ? `Airbnb listing: ${airbnbImportListingUrl.trim()}` : "",
      ]
        .filter(Boolean)
        .join("\n");

      const created = await createPropertyViaAdminApi({
        name: airbnbImportName.trim(),
        address: buildPropertyAddress([
          airbnbImportStreet,
          airbnbImportCity,
          airbnbImportProvince,
          airbnbImportPostal,
        ]),
        notes: combinedNotes || null,
        coverPhotoUrl: airbnbImportCoverPhotoUrl,
        defaultCleanerUnitsNeeded: Number(propertyUnitsNeeded),
        cleanerUnitsRequiredStrict: propertyUnitsStrict,
        showTeamStatusToCleaners: propertyShowTeamStatus,
        ownerEmail: airbnbImportOwnerEmail,
        ownerName: airbnbImportOwnerName,
        calendarSource: "airbnb",
        calendarUrl: normalizedCalendarUrl,
      });

      const insertedProperty = created.property;
      if (!insertedProperty?.id) throw new Error("Could not create Airbnb property.");
      if (created?.geocodeWarning) {
        setError(String(created.geocodeWarning));
      }

      insertedPropertyId = insertedProperty.id;

      setSelectedPropertyId(insertedProperty.id);
      setPropertySetupTab("overview");

      const {
        data: { session },
      } = await supabase.auth.getSession();

      if (!session?.access_token) {
        throw new Error("Property created, but the calendar could not sync because your admin session was not ready.");
      }

      const syncResponse = await fetch("/api/sync-calendars", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${session.access_token}`,
        },
        body: JSON.stringify({
          organizationId: currentOrganizationId,
          propertyId: insertedProperty.id,
        }),
      });

      const syncPayload = await syncResponse.json().catch(() => null);
      if (!syncResponse.ok) {
        throw new Error(
          `Property and Airbnb calendar were saved, but automatic sync failed: ${syncPayload?.error || syncPayload?.message || "Calendar sync failed."}`
        );
      }

      resetAirbnbImportForm();
      setActionMessage(`Airbnb property imported and synced automatically. ${getCalendarSyncMessage(syncPayload)}`);
      await loadData();
    } catch (err: any) {
      if (insertedPropertyId) {
        await loadData();
      }
      setError(err?.message || "Could not import Airbnb property.");
    } finally {
      setImportingAirbnbProperty(false);
    }
  }
  async function createOrganizationInvite(params: {
    email: string;
    fullName?: string;
    phone?: string;
    role: OrganizationInviteRole;
  }) {
    const email = params.email.trim().toLowerCase();
    const fullName = params.fullName?.trim() || null;
    const phone = params.phone?.trim() || null;

    if (!currentOrganizationId) {
      setError("No organization selected.");
      return null;
    }

    if (!currentAdminUserId) {
      setError("No admin user found.");
      return null;
    }

    if (!email) {
      setError("Email is required.");
      return null;
    }

    if (params.role === "admin" && !canManageAdminAccess) {
      setError("Only the primary admin or platform owner can invite another admin.");
      return null;
    }

    setError("");
    setActionMessage("");

    if (params.role === "admin") {
      const {
        data: { session },
        error: sessionError,
      } = await supabase.auth.getSession();

      if (sessionError || !session?.access_token) {
        setError("Could not verify your admin session.");
        return null;
      }

      try {
        const response = await fetch("/api/admin/admin-invite", {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
            Authorization: `Bearer ${session.access_token}`,
          },
          body: JSON.stringify({
            organizationId: currentOrganizationId,
            email,
            fullName,
            phone,
          }),
        });

        const payload = await response.json().catch(() => null);

        if (!response.ok) {
          throw new Error(payload?.error || "Could not send admin invite.");
        }

        setActionMessage(
          payload?.refreshed
            ? `admin invite refreshed and email sent: ${payload.inviteUrl}`
            : `admin invite created and email sent: ${payload.inviteUrl}`
        );
        await loadData();
        return payload.invite;
      } catch (err) {
        setError(err instanceof Error ? err.message : "Could not send admin invite.");
        return null;
      }
    }

    const token = createInviteToken();

    const expiresAt = new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString();
    const { data: existingInvite, error: existingInviteError } = await supabase
      .from("organization_invites")
      .select("*")
      .eq("organization_id", currentOrganizationId)
      .eq("email", email)
      .eq("role", params.role)
      .in("status", ["pending", "sent"])
      .order("created_at", { ascending: false })
      .limit(1)
      .maybeSingle();

    if (existingInviteError) {
      setError(existingInviteError.message);
      return null;
    }

    const { data, error } = existingInvite
      ? await supabase
        .from("organization_invites")
        .update({
          full_name: fullName || existingInvite.full_name,
          phone: phone || existingInvite.phone,
          status: "sent",
          token,
          sent_at: new Date().toISOString(),
          expires_at: expiresAt,
        })
        .eq("id", existingInvite.id)
        .select()
        .single()
      : await supabase
        .from("organization_invites")
        .insert({
          organization_id: currentOrganizationId,
          email,
          full_name: fullName,
          phone,
          role: params.role,
          status: "sent",
          token,
          invited_by_profile_id: currentAdminUserId,
          sent_at: new Date().toISOString(),
          expires_at: expiresAt,
        })
        .select()
        .single();

    if (error) {
      setError(error.message);
      return null;
    }

    const inviteUrl = `${window.location.origin}/invite?token=${data.token}`;

    try {
      const {
        data: { session },
        error: sessionError,
      } = await supabase.auth.getSession();

      if (sessionError || !session?.access_token) {
        throw new Error("Could not verify your admin session.");
      }

      const response = await fetch("/api/send-invite-email", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${session.access_token}`,
        },
        body: JSON.stringify({
          email,
          inviteUrl,
          role: params.role,
          name: fullName,
        }),
      });

      const payload = await response.json().catch(() => null);

      if (!response.ok) {
        const detailedError =
          payload?.error ||
          payload?.message ||
          `Invite email failed with status ${response.status}`;
        throw new Error(detailedError);
      }

      setActionMessage(
        existingInvite
          ? `${params.role} invite refreshed and email sent: ${inviteUrl}`
          : `${params.role} invite created and email sent: ${inviteUrl}`
      );
    } catch (err: any) {
      const detailedMessage = err?.message || "Unknown email send error.";
      setError(detailedMessage);
      setActionMessage(
        existingInvite
          ? `${params.role} invite refreshed, but email failed to send: ${detailedMessage}`
          : `${params.role} invite created, but email failed to send: ${detailedMessage}`
      );
    }

    return data;
  }
  async function resendOrganizationInvite(params: {
    email: string;
    role: OrganizationInviteRole;
  }) {
    const email = params.email.trim().toLowerCase();

    if (!currentOrganizationId) {
      setError("No organization selected.");
      return null;
    }

    if (!email) {
      setError("Email is required.");
      return null;
    }

    if (params.role === "admin" && !canManageAdminAccess) {
      setError("Only the primary admin or platform owner can resend admin invites.");
      return null;
    }

    setError("");
    setActionMessage("");

    if (params.role === "admin") {
      const {
        data: { session },
        error: sessionError,
      } = await supabase.auth.getSession();

      if (sessionError || !session?.access_token) {
        setError("Could not verify your admin session.");
        return null;
      }

      try {
        const response = await fetch("/api/admin/admin-invite", {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
            Authorization: `Bearer ${session.access_token}`,
          },
          body: JSON.stringify({
            organizationId: currentOrganizationId,
            email,
          }),
        });

        const payload = await response.json().catch(() => null);

        if (!response.ok) {
          throw new Error(payload?.error || "Could not resend admin invite.");
        }

        setActionMessage(`admin invite resent and email sent: ${payload.inviteUrl}`);
        await loadData();
        return payload.invite;
      } catch (err) {
        setError(err instanceof Error ? err.message : "Could not resend admin invite.");
        return null;
      }
    }

    const { data: existingInvite, error: existingInviteError } = await supabase
      .from("organization_invites")
      .select("*")
      .eq("organization_id", currentOrganizationId)
      .eq("email", email)
      .eq("role", params.role)
      .in("status", ["pending", "sent"])
      .order("created_at", { ascending: false })
      .limit(1)
      .maybeSingle();

    if (existingInviteError) {
      setError(existingInviteError.message);
      return null;
    }

    if (!existingInvite) {
      setError("No active invite was found to resend.");
      return null;
    }

    const refreshedExpiry = new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString();
    const refreshedToken = createInviteToken();

    const { data, error } = await supabase
      .from("organization_invites")
      .update({
        sent_at: new Date().toISOString(),
        expires_at: refreshedExpiry,
        status: "sent",
        token: refreshedToken,
      })
      .eq("id", existingInvite.id)
      .select()
      .single();

    if (error) {
      setError(error.message);
      return null;
    }

    const inviteUrl = `${window.location.origin}/invite?token=${data.token}`;

    try {
      const {
        data: { session },
        error: sessionError,
      } = await supabase.auth.getSession();

      if (sessionError || !session?.access_token) {
        throw new Error("Could not verify your admin session.");
      }

      const response = await fetch("/api/send-invite-email", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${session.access_token}`,
        },
        body: JSON.stringify({
          email,
          inviteUrl,
          role: params.role,
          name: data.full_name || undefined,
        }),
      });

      const payload = await response.json().catch(() => null);

      if (!response.ok) {
        throw new Error(payload?.error || "Invite email failed to send.");
      }

      setActionMessage(`${params.role} invite resent and email sent: ${inviteUrl}`);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Invite email failed to send.");
      setActionMessage(`${params.role} invite was refreshed, but email failed to send: ${inviteUrl}`);
    }

    return data;
  }

