  async function updateCleanerAssignmentMode(property: Property, mode: "priority" | "training_rotation") {
    const propertyAssignments = getCleanerAssignmentsForProperty(property.id);
    if (mode === "training_rotation" && propertyAssignments.length < 2) {
      setError("Add at least two cleaner assignments before turning on Training Rotation.");
      return;
    }

    setSavingCleanerRotationPropertyId(property.id);
    setError("");
    setActionMessage("");

    try {
      const nextCleanerId =
        mode === "training_rotation"
          ? property.cleaner_rotation_next_cleaner_account_id || propertyAssignments[0]?.cleaner_account_id || null
          : null;

      const { error } = await supabase
        .from("properties")
        .update({
          cleaner_assignment_mode: mode,
          cleaner_rotation_next_cleaner_account_id: nextCleanerId,
        })
        .eq("id", property.id)
        .eq("organization_id", currentOrganizationId);

      if (error) throw error;

      setProperties((rows) =>
        rows.map((row) =>
          row.id === property.id
            ? {
                ...row,
                cleaner_assignment_mode: mode,
                cleaner_rotation_next_cleaner_account_id: nextCleanerId,
              }
            : row
        )
      );
      setActionMessage(
        mode === "training_rotation"
          ? `Training Rotation turned on for ${property.name || property.address || "property"}.`
          : `Primary/backup mode restored for ${property.name || property.address || "property"}.`
      );
    } catch (err: unknown) {
      setError(getErrorMessage(err, "Could not update cleaner assignment mode. Run the Training Rotation SQL first if you have not already."));
    } finally {
      setSavingCleanerRotationPropertyId(null);
    }
  }

  async function finishCleanerTrainingRotation(property: Property, primaryCleanerAccountId: string) {
    const propertyAssignments = getCleanerAssignmentsForProperty(property.id);
    if (propertyAssignments.length === 0) return;

    const confirmed = window.confirm(
      `Make ${getCleanerAccountName(primaryCleanerAccountId)} the primary cleaner for ${property.name || property.address || "this property"}?\n\nTraining Rotation will turn off and the remaining cleaner assignments will become backups.`
    );
    if (!confirmed) return;

    setSavingCleanerRotationPropertyId(property.id);
    setError("");
    setActionMessage("");

    try {
      const orderedAssignments = [
        ...propertyAssignments.filter((assignment) => assignment.cleaner_account_id === primaryCleanerAccountId),
        ...propertyAssignments.filter((assignment) => assignment.cleaner_account_id !== primaryCleanerAccountId),
      ];

      for (let index = 0; index < orderedAssignments.length; index += 1) {
        const { error: assignmentError } = await supabase
          .from("property_cleaner_account_assignments")
          .update({ priority: Math.min(index + 1, 3) })
          .eq("id", orderedAssignments[index].id);

        if (assignmentError) throw assignmentError;
      }

      const { error: propertyError } = await supabase
        .from("properties")
        .update({
          cleaner_assignment_mode: "priority",
          cleaner_rotation_next_cleaner_account_id: null,
        })
        .eq("id", property.id)
        .eq("organization_id", currentOrganizationId);

      if (propertyError) throw propertyError;

      setActionMessage(`${getCleanerAccountName(primaryCleanerAccountId)} is now primary for ${property.name || property.address || "property"}.`);
      await loadData();
    } catch (err: unknown) {
      setError(getErrorMessage(err, "Could not finish Training Rotation."));
    } finally {
      setSavingCleanerRotationPropertyId(null);
    }
  }

  async function createJob() {
    if (!jobPropertyId) return;

    const property = properties.find((p) => p.id === jobPropertyId);
    const extractedDate = extractCheckoutDate(jobNotes.trim() || null);
    const scheduledDate = jobScheduledFor || extractedDate;

    if (!scheduledDate) {
      setError("Please select a cleaning date or include a checkout date in the notes.");
      return;
    }

    const payload: Partial<Job> & {
      organization_id: string | null;
      property_id: string;
      cleaners_needed: number;
      cleaners_required_strict: boolean;
      notes: string | null;
      scheduled_for: string | null;
    } = {
      organization_id: currentOrganizationId,
      property_id: jobPropertyId,
      cleaners_needed: Number(jobUnitsNeeded),
      cleaners_required_strict: jobUnitsStrict,
      notes: jobNotes.trim() || null,
      scheduled_for: scheduledDate,
    };

    if (jobOverrideUnitsEnabled) {
      payload.cleaner_units_needed = Number(jobUnitsNeeded);
      payload.cleaner_units_required_strict = jobUnitsStrict;
      payload.show_team_status_to_cleaners = jobShowTeamStatus;
    } else if (property) {
      payload.cleaner_units_needed = property.default_cleaner_units_needed;
      payload.cleaner_units_required_strict = property.cleaner_units_required_strict;
      payload.show_team_status_to_cleaners = property.show_team_status_to_cleaners;
    }

    setError("");
    setActionMessage("");

    const {
      data: { session },
      error: sessionError,
    } = await supabase.auth.getSession();

    if (sessionError || !session?.access_token) {
      const message = "Could not verify your admin session.";
      setError(message);
      alert(message);
      return;
    }

    const response = await fetch("/api/admin/cleaning-job", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${session.access_token}`,
      },
      body: JSON.stringify({
        organizationId: payload.organization_id,
        propertyId: payload.property_id,
        cleanersNeeded: payload.cleaners_needed,
        cleanersRequiredStrict: payload.cleaners_required_strict,
        cleanerUnitsNeeded: payload.cleaner_units_needed,
        cleanerUnitsRequiredStrict: payload.cleaner_units_required_strict,
        showTeamStatusToCleaners: payload.show_team_status_to_cleaners,
        notes: payload.notes,
        scheduledFor: payload.scheduled_for,
      }),
    });

    const result = await response.json().catch(() => null);

    if (!response.ok || !result?.ok) {
      const message = result?.error || "Could not create job.";
      setError(message);
      alert(message);
      await loadData();
      return;
    }

    const notification = result.notification || {};
    let notificationNote = "";
    const emailSent = Number(notification.sent || 0);
    const pushSent = Number(notification.pushSent || 0);
    if ((notification.errors ?? []).length > 0) {
      notificationNote = ` Job notification needs attention: ${notification.errors[0]}`;
    } else if (emailSent > 0 || pushSent > 0) {
      const parts = [];
      if (emailSent > 0) parts.push(`${emailSent} email${emailSent === 1 ? "" : "s"}`);
      if (pushSent > 0) parts.push(`${pushSent} push alert${pushSent === 1 ? "" : "s"}`);
      notificationNote = ` ${parts.join(" and ")} sent.`;
    }

    setJobPropertyId("");
    setJobScheduledFor("");
    setJobNotes("");
    setJobOverrideUnitsEnabled(false);
    setJobUnitsNeeded("1");
    setJobUnitsStrict(false);
    setJobShowTeamStatus(true);
    setActionMessage(`Job created successfully.${notificationNote}`.trim());
    alert(`Cleaning job created.${notificationNote}`.trim());
    await loadData();
    setActiveSection("jobs");
    setHighlightedJobId(result.jobId);
    setTimeout(() => {
      document.getElementById(`job-${result.jobId}`)?.scrollIntoView({
        behavior: "smooth",
        block: "center",
      });
    }, 150);
  }

