  async function reassignStrandedJob(jobId: string) {
    const cleanerAccountId = reassignSelections[jobId];
    if (!cleanerAccountId) {
      setError("Please select a cleaner account before assigning.");
      return;
    }

    const job = strandedJobs.find((item) => item.id === jobId) || jobs.find((item) => item.id === jobId);
    const cleanerIsAssignedToProperty = getCleanerAccountsForProperty(job?.property_id || null).some(
      (account) => account.id === cleanerAccountId
    );
    if (!cleanerIsAssignedToProperty) {
      setError("That cleaner is not assigned to this property. Add them on the Assignments tab first.");
      return;
    }

    const slot = jobSlots
      .filter((x) => x.job_id === jobId)
      .sort((a, b) => a.slot_number - b.slot_number)
      .find((x) => x.status === "stranded" || x.cleaner_account_id === null);

    if (!slot) {
      setError("No stranded slot was found for that job.");
      return;
    }

    setError("");
    setReassigningJobId(jobId);

    try {
      if (!currentOrganizationId) {
        throw new Error("No organization selected.");
      }

      const {
        data: { session },
        error: sessionError,
      } = await supabase.auth.getSession();

      if (sessionError || !session?.access_token) {
        throw new Error("Could not verify your admin session.");
      }

      const response = await fetch("/api/admin/stranded-job", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${session.access_token}`,
        },
        body: JSON.stringify({
          action: "reassign",
          organizationId: currentOrganizationId,
          jobId,
          cleanerAccountId,
        }),
      });

      const payload = await response.json().catch(() => null);

      if (!response.ok || !payload?.ok) {
        throw new Error(payload?.error || "Could not reassign stranded job.");
      }

      const notifyResult = payload.notificationResult || {};
      const sentCount = Number(notifyResult.sent ?? 0);
      const pushSentCount = Number(notifyResult.pushSent ?? 0);
      const notificationErrors = Array.isArray(notifyResult.errors) ? notifyResult.errors : [];

      setActionMessage(
        notificationErrors.length > 0
          ? `Stranded job reassigned. Job notification needs attention: ${notificationErrors[0]}`
          : sentCount > 0 || pushSentCount > 0
            ? `Stranded job reassigned. ${sentCount} email${sentCount === 1 ? "" : "s"} and ${pushSentCount} push alert${pushSentCount === 1 ? "" : "s"} sent.`
            : "Stranded job reassigned."
      );
      await loadData();
    } catch (err: any) {
      setError(err?.message || "Could not reassign stranded job.");
    } finally {
      setReassigningJobId(null);
    }
  }

