  async function uploadSelectedPropertyCoverPhoto(e: ChangeEvent<HTMLInputElement>) {
    const file = e.target.files?.[0] || null;
    e.target.value = "";

    if (!selectedPropertyId) {
      setError("Please select a property first.");
      setPropertyCoverError("Please select a property first.");
      return;
    }

    if (!file) return;

    if (!file.type.startsWith("image/")) {
      setError("Please choose an image file for the cover photo.");
      setPropertyCoverError("Please choose an image file for the cover photo.");
      return;
    }

    setError("");
    setActionMessage("");
    setPropertyCoverError("");
    setPropertyCoverMessage("Uploading cover photo...");
    setUploadingPropertyCover(true);

    try {
      const safeName = file.name.replace(/[^a-zA-Z0-9._-]/g, "_");
      const filePath = `${selectedPropertyId}/cover/${Date.now()}-${safeName}`;

      const { error: uploadError } = await supabase.storage
        .from("property-sop-images")
        .upload(filePath, file, { cacheControl: "3600", upsert: false });

      if (uploadError) throw uploadError;

      const {
        data: { publicUrl },
      } = supabase.storage.from("property-sop-images").getPublicUrl(filePath);

      const updatedProperty = await savePropertyCoverPhotoUrl(publicUrl);

      setProperties((prev) =>
        prev.map((property) =>
          property.id === selectedPropertyId
            ? { ...property, ...updatedProperty, cover_photo_url: publicUrl }
            : property
        )
      );
      setPropertyCoverMessage("Cover photo uploaded.");
      setActionMessage("Property cover photo updated.");
      await loadData();
    } catch (err: any) {
      const message = err?.message || "Could not upload property cover photo.";
      const helpfulMessage = message.includes("cover_photo_url")
        ? `${message} Run supabase/add_property_cover_photo.sql in Supabase, then try again.`
        : message;
      setPropertyCoverError(helpfulMessage);
      setPropertyCoverMessage("");
      setError(helpfulMessage);
    } finally {
      setUploadingPropertyCover(false);
    }
  }

  async function saveSelectedPropertyManualDetails() {
    if (!selectedPropertyId) return;
    if (!currentOrganizationId) {
      setError("Choose an organization before saving property details.");
      return;
    }

    setError("");
    setSavingSelectedPropertyManualDetails(true);
    const savedAnchorDate =
      selectedPropertyWastePattern === "biweekly_same" || selectedPropertyWastePattern === "alternating"
        ? selectedPropertyGarbageRotationAnchorDate || null
        : null;
    const savedGarbageDay =
      selectedPropertyWastePattern === "alternating"
        ? null
        : selectedPropertyGarbageDay.trim() || null;
    const savedWeekALabel =
      selectedPropertyWastePattern === "alternating"
        ? selectedPropertyGarbageWeekALabel.trim() || "Garbage + recycling"
        : selectedPropertyGarbageDay.trim() || "Waste pickup";
    const savedWeekBLabel =
      selectedPropertyWastePattern === "alternating"
        ? selectedPropertyGarbageWeekBLabel.trim() || "Recycling only"
        : selectedPropertyWastePattern === "biweekly_same"
          ? "No pickup"
          : "No pickup";

    try {
      const {
        data: { session },
        error: sessionError,
      } = await supabase.auth.getSession();

      if (sessionError || !session?.access_token) {
        throw new Error("No active admin session was found.");
      }

      const response = await fetch("/api/admin/property-details", {
        method: "POST",
        cache: "no-store",
        headers: {
          Authorization: `Bearer ${session.access_token}`,
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          organizationId: currentOrganizationId,
          propertyId: selectedPropertyId,
          wifiNetwork: selectedPropertyWifiNetwork,
          wifiPassword: selectedPropertyWifiPassword,
          garbageDay: savedGarbageDay,
          garbageNotes: selectedPropertyGarbageNotes,
          garbagePickupWeekday: selectedPropertyGarbagePickupWeekday,
          garbageRotationAnchorDate: savedAnchorDate,
          garbageWeekALabel: savedWeekALabel,
          garbageWeekBLabel: savedWeekBLabel,
          latitude: selectedPropertyLatitude,
          longitude: selectedPropertyLongitude,
          defaultCheckinTime: selectedPropertyDefaultCheckinTime,
          defaultCheckoutTime: selectedPropertyDefaultCheckoutTime,
        }),
      });
      const payload = await response.json().catch(() => null);

      if (!response.ok || !payload?.ok) {
        throw new Error(payload?.error || "Could not save property details.");
      }

      if (payload.property) {
        setProperties((current) =>
          current.map((property) =>
            property.id === selectedPropertyId ? { ...property, ...payload.property } : property
          )
        );
      }

      setPropertyManualDetailsDirty(false);
      setActionMessage("Property details saved.");
      if (payload?.geocodeWarning) {
        setError(String(payload.geocodeWarning));
      }
      await loadData();
    } catch (err: any) {
      const message = String(err?.message || "Could not save property details.");
      setError(
        message.includes("wifi_network") || message.includes("garbage_")
          ? `${message} Run supabase/add_property_inspections.sql first.`
          : message.includes("default_check")
            ? `${message} Run supabase/add_property_default_times.sql first.`
          : message.includes("latitude") || message.includes("longitude")
            ? `${message} Run supabase/add_property_location_coordinates.sql first.`
          : message
      );
    } finally {
      setSavingSelectedPropertyManualDetails(false);
    }
  }

  function normalizeInspectionChecks(text: string) {
    return text
      .split(/\r?\n/)
      .map((line) => line.trim())
      .filter(Boolean)
      .map((label) => ({ label, required: true }));
  }

  function getInspectionCheckLabel(check: string | { label?: string; title?: string }) {
    return typeof check === "string" ? check : check.label || check.title || "Inspection item";
  }

  function getNextInspectionDueDate(rule: PropertyInspectionRule, fromDate = new Date()) {
    const next = new Date(fromDate);
    const interval = Math.max(1, Number(rule.interval_count || 1));

    if (rule.frequency_type === "weekly") next.setDate(next.getDate() + interval * 7);
    else if (rule.frequency_type === "quarterly") next.setMonth(next.getMonth() + interval * 3);
    else if (rule.frequency_type === "yearly") next.setFullYear(next.getFullYear() + interval);
    else if (rule.frequency_type === "custom_days") next.setDate(next.getDate() + interval);
    else next.setMonth(next.getMonth() + interval);

    return toYmd(next);
  }

  async function saveInspectionRule() {
    if (!currentOrganizationId || !inspectionPropertyId) {
      setError("Choose a property for this inspection rule.");
      return;
    }

    const checks = normalizeInspectionChecks(inspectionRuleChecksText);
    if (!inspectionRuleTitle.trim() || checks.length === 0) {
      setError("Inspection title and at least one check are required.");
      return;
    }

    setError("");
    setSavingInspectionRule(true);

    try {
      const { error } = await supabase.from("property_inspection_rules").insert({
        organization_id: currentOrganizationId,
        property_id: inspectionPropertyId,
        title: inspectionRuleTitle.trim(),
        frequency_type: inspectionRuleFrequency,
        interval_count: Number(inspectionRuleInterval || "1"),
        next_due_date: inspectionRuleNextDueDate || todayYmd,
        checks,
        notes: inspectionRuleNotes.trim() || null,
        created_by_profile_id: currentAdminUserId || null,
      });

      if (error) throw error;
      setActionMessage("Inspection rule saved.");
      setInspectionRuleTitle("Monthly safety inspection");
      setInspectionRuleFrequency("monthly");
      setInspectionRuleInterval("1");
      setInspectionRuleNextDueDate("");
      setInspectionRuleChecksText("Fire extinguishers\nSmoke alarms");
      setInspectionRuleNotes("");
      await loadData();
    } catch (err: any) {
      const message = String(err?.message || "Could not save inspection rule.");
      setError(message.includes("property_inspection_rules") ? `${message} Run supabase/add_property_inspections.sql first.` : message);
    } finally {
      setSavingInspectionRule(false);
    }
  }

