  async function uploadDocumentVaultFiles() {
    if (!currentOrganizationId) {
      setError("No organization selected.");
      return;
    }

    if (documentVaultFiles.length === 0) {
      setError("Choose at least one document to upload.");
      return;
    }

    setError("");
    setActionMessage("");
    setUploadingDocumentVaultFiles(true);

    try {
      for (let i = 0; i < documentVaultFiles.length; i++) {
        const file = documentVaultFiles[i];
        const safeName = file.name.replace(/[^a-zA-Z0-9._-]/g, "_");
        const propertySegment = documentVaultPropertyId === "all" ? "organization" : documentVaultPropertyId;
        const filePath = `${currentOrganizationId}/${propertySegment}/${Date.now()}-${i}-${safeName}`;

        const { error: uploadError } = await supabase.storage
          .from("document-vault")
          .upload(filePath, file, { cacheControl: "3600", upsert: false });

        if (uploadError) {
          throw new Error(uploadError.message);
        }

        const { error: insertError } = await supabase.from("document_vault_files").insert({
          organization_id: currentOrganizationId,
          property_id: documentVaultPropertyId === "all" ? null : documentVaultPropertyId,
          title: documentVaultTitle.trim() || file.name.replace(/\.[^.]+$/, ""),
          category: documentVaultCategory,
          file_name: file.name,
          file_size: file.size,
          mime_type: file.type || null,
          storage_path: filePath,
          created_by_profile_id: currentAdminUserId,
        });

        if (insertError) {
          await supabase.storage.from("document-vault").remove([filePath]);
          throw new Error(insertError.message);
        }
      }

      setDocumentVaultTitle("");
      setDocumentVaultFiles([]);
      setActionMessage(`${documentVaultFiles.length} document${documentVaultFiles.length === 1 ? "" : "s"} uploaded.`);
      await loadData();
    } catch (err) {
      setError(getErrorMessage(err, "Could not upload document. Run the document vault SQL first if the table or bucket is missing."));
    } finally {
      setUploadingDocumentVaultFiles(false);
    }
  }

  async function openDocumentVaultFile(document: DocumentVaultRow) {
    setOpeningDocumentVaultId(document.id);
    setError("");

    try {
      const { data, error } = await supabase.storage
        .from("document-vault")
        .createSignedUrl(document.storage_path, 10 * 60, {
          download: document.file_name,
        });

      if (error || !data?.signedUrl) {
        throw new Error(error?.message || "Could not create download link.");
      }

      window.open(data.signedUrl, "_blank", "noopener,noreferrer");
    } catch (err) {
      setError(getErrorMessage(err, "Could not open this document."));
    } finally {
      setOpeningDocumentVaultId(null);
    }
  }

  async function deleteDocumentVaultFile(document: DocumentVaultRow) {
    const confirmed = window.confirm(`Delete ${document.title || document.file_name}? This removes it from the document vault.`);
    if (!confirmed) return;

    setDeletingDocumentVaultId(document.id);
    setError("");
    setActionMessage("");

    try {
      const { error: deleteError } = await supabase
        .from("document_vault_files")
        .delete()
        .eq("id", document.id);

      if (deleteError) throw deleteError;

      await supabase.storage.from("document-vault").remove([document.storage_path]);
      setDocumentVaultRows((rows) => rows.filter((row) => row.id !== document.id));
      setActionMessage("Document deleted.");
    } catch (err) {
      setError(getErrorMessage(err, "Could not delete document."));
    } finally {
      setDeletingDocumentVaultId(null);
    }
  }

  function getPropertyName(id: string | null) {
    if (!id) return "Unknown property";
    return properties.find((p) => p.id === id)?.name || id;
  }

  function getWeekdayLabel(value: number | null | undefined) {
    if (typeof value !== "number") return "No pickup day saved";
    return WEEKDAY_OPTIONS.find((option) => option.value === String(value))?.label || "Unknown weekday";
  }

  function getWastePatternLabel(property: Property) {
    const pattern = inferWastePattern(property);
    if (pattern === "biweekly_same") return "Every 2 weeks";
    if (pattern === "alternating") return "Alternating weeks";
    return "Every week";
  }

  function getCleanerAccountName(id: string | null) {
    if (!id) return "Unassigned";
    return cleanerAccounts.find((c) => c.id === id)?.display_name || id;
  }

  function getCleanerAssignmentsForProperty(propertyId: string) {
    return assignments
      .filter((assignment) => {
        if (assignment.property_id !== propertyId) return false;
        const account = cleanerAccounts.find((item) => item.id === assignment.cleaner_account_id);
        return account?.active !== false;
      })
      .sort((a, b) => a.priority - b.priority);
  }

  function getCleanerAccountsForProperty(propertyId: string | null) {
    if (!propertyId) return [];

    return getCleanerAssignmentsForProperty(propertyId)
      .map((assignment) => cleanerAccounts.find((account) => account.id === assignment.cleaner_account_id) || null)
      .filter((account): account is CleanerAccount => !!account);
  }

  function getTrainingRotationOrder(property: Property | null | undefined) {
    if (!property) return [];
    const propertyAssignments = getCleanerAssignmentsForProperty(property.id);
    if (propertyAssignments.length === 0) return [];

    const nextCleanerId = property.cleaner_rotation_next_cleaner_account_id;
    const startIndex = nextCleanerId
      ? propertyAssignments.findIndex((assignment) => assignment.cleaner_account_id === nextCleanerId)
      : -1;

    if (startIndex <= 0) return propertyAssignments;
    return [...propertyAssignments.slice(startIndex), ...propertyAssignments.slice(0, startIndex)];
  }

  function getGroundsAccountName(id: string | null) {
    if (!id) return "Unassigned";
    return groundsAccounts.find((g) => g.id === id)?.display_name || id;
  }

  function getGroundsTaskLabel(task: GroundsRecurringTask) {
    return task.label || task.task_type || "Recurring grounds task";
  }


  function getGroundsRuleLabel(rule: GroundsRecurringRule) {
    return rule.label || rule.task_type || "Recurring grounds rule";
  }

  function getGroundsRuleFrequencyLabel(rule: GroundsRecurringRule) {
    if (rule.frequency_type === "weekly") {
      return `Weekly${rule.day_of_week !== null ? ` • day ${rule.day_of_week}` : ""}`;
    }
    if (rule.frequency_type === "biweekly") {
      return `Biweekly${rule.day_of_week !== null ? ` • day ${rule.day_of_week}` : ""}`;
    }
    if (rule.frequency_type === "monthly") {
      return `Monthly${rule.day_of_month !== null ? ` • day ${rule.day_of_month}` : ""}`;
    }
    if (rule.frequency_type === "semi_monthly") {
      const parts = [rule.semi_monthly_day_1, rule.semi_monthly_day_2].filter((v) => v !== null);
      return parts.length ? `Semi-monthly • days ${parts.join(" & ")}` : "Semi-monthly";
    }
    if (rule.frequency_type === "every_x_days") {
      return rule.interval_days ? `Every ${rule.interval_days} days` : "Every X days";
    }
    return rule.frequency_type || "Custom";
  }

  function getPriorityLabel(priority: number) {
    if (priority === 1) return "Primary";
    if (priority === 2) return "Backup";
    if (priority === 3) return "Second Backup";
    return `Priority ${priority}`;
  }

  function formatDateTime(value?: string | null) {
    if (!value) return "Unknown time";
    const date = new Date(value);
    if (Number.isNaN(date.getTime())) return value;
    const dateLabel = formatLongDate(date);
    const timeLabel = date.toLocaleTimeString(undefined, {
      hour: "numeric",
      minute: "2-digit",
    });
    return `${dateLabel}, ${timeLabel}`;
  }

  function formatScheduledFor(value?: string | null) {
    if (!value) return "Not set";
    const d = new Date(`${value}T12:00:00`);
    if (Number.isNaN(d.getTime())) return value;
    return formatLongDate(d);
  }

  function formatFileSize(bytes?: number | null) {
    if (!bytes || bytes <= 0) return "Unknown size";
    if (bytes < 1024) return `${bytes} B`;
    if (bytes < 1024 * 1024) return `${Math.round(bytes / 102.4) / 10} KB`;
    return `${Math.round(bytes / (1024 * 102.4)) / 10} MB`;
  }

  function getMaintenanceFlagLabel(flag: MaintenanceFlagRow, keys: string[]) {
    return (
      flag.title ||
      flag.name ||
      flag.issue ||
      flag.flag ||
      flag.category ||
      (keys.length > 0 ? keys[0].replace(/_/g, " ") : "Untitled flag")
    );
  }

  function getMaintenanceFlagBody(flag: MaintenanceFlagRow) {
    return flag.description || flag.notes || flag.details || flag.summary || null;
  }

  function getMaintenanceFlagState(flag: MaintenanceFlagRow) {
    if (flag.resolved_at) return "resolved";
    return flag.status || "open";
  }

  function isMaintenanceFlagResolved(flag: MaintenanceFlagRow) {
    const stateLower = String(getMaintenanceFlagState(flag) || "").toLowerCase();
    return stateLower.includes("resolved") || stateLower.includes("closed") || stateLower.includes("done");
  }

  function getMaintenanceFlagSnoozedUntil(flagId: string) {
    const value = maintenanceFlagSnoozes[flagId];
    if (!value) return null;
    const date = new Date(value);
    return Number.isNaN(date.getTime()) ? null : date;
  }

  function isMaintenanceFlagSnoozed(flag: MaintenanceFlagRow) {
    if (isMaintenanceFlagResolved(flag)) return false;
    const snoozedUntil = getMaintenanceFlagSnoozedUntil(flag.id);
    return !!snoozedUntil && snoozedUntil.getTime() > now.getTime();
  }

  function snoozeMaintenanceFlag(flag: MaintenanceFlagRow) {
    if (!flag.owner_notified_at) {
      setError("Email the owner before snoozing this maintenance flag.");
      return;
    }

    const snoozedUntil = new Date();
    snoozedUntil.setDate(snoozedUntil.getDate() + MAINTENANCE_FLAG_SNOOZE_DAYS);

    setMaintenanceFlagSnoozes((current) => ({
      ...current,
      [flag.id]: snoozedUntil.toISOString(),
    }));
    setActionMessage(
      `Maintenance flag hidden until ${formatLongDate(snoozedUntil)} unless it is marked resolved first.`
    );
  }

  function unsnoozeMaintenanceFlag(flagId: string) {
    setMaintenanceFlagSnoozes((current) => {
      const next = { ...current };
      delete next[flagId];
      return next;
    });
  }

  function resetMaintenanceForm() {
    setMaintenanceFormPropertyId(selectedJobsPropertyFilter !== "all" ? selectedJobsPropertyFilter : "");
    setMaintenanceFormCategory("");
    setMaintenanceFormUrgency("normal");
    setMaintenanceFormNotes("");
    setMaintenanceFormFiles([]);
    setMaintenanceFormError("");
  }

  function appendMaintenanceFormFiles(files: FileList | null) {
    if (!files?.length) return;
    setMaintenanceFormFiles((current) => [...current, ...Array.from(files)]);
    setMaintenanceFormError("");
  }

  function removeMaintenanceFormFile(indexToRemove: number) {
    setMaintenanceFormFiles((current) => current.filter((_, index) => index !== indexToRemove));
  }

  async function uploadMaintenanceFlagImages(flagId: string) {
    if (maintenanceFormFiles.length === 0) return 0;

    const uploads: Array<{ flag_id: string; image_url: string; caption: null; sort_order: number }> = [];

    for (let index = 0; index < maintenanceFormFiles.length; index += 1) {
      const file = maintenanceFormFiles[index];
      const safeName = file.name.replace(/[^a-zA-Z0-9._-]/g, "_");
      const filePath = `${flagId}/${Date.now()}-${index}-${safeName}`;

      const { error: uploadError } = await supabase.storage
        .from("maintenance-flag-images")
        .upload(filePath, file, { cacheControl: "3600", upsert: false });

      if (uploadError) {
        throw new Error(`Photo upload failed: ${uploadError.message}`);
      }

      const {
        data: { publicUrl },
      } = supabase.storage.from("maintenance-flag-images").getPublicUrl(filePath);

      uploads.push({
        flag_id: flagId,
        image_url: publicUrl,
        caption: null,
        sort_order: index,
      });
    }

    const { error: imageInsertError } = await supabase.from("property_maintenance_flag_images").insert(uploads);
    if (imageInsertError) {
      throw new Error(`Photo record save failed: ${imageInsertError.message}`);
    }

    return uploads.length;
  }

  function openMaintenanceModal() {
    resetMaintenanceForm();
    setMaintenanceModalOpen(true);
  }

  function closeMaintenanceModal() {
    setMaintenanceModalOpen(false);
    resetMaintenanceForm();
  }

  async function createMaintenanceFlag() {
    if (!currentOrganizationId) {
      setMaintenanceFormError("Choose an organization before creating a maintenance flag.");
      return;
    }

    if (!maintenanceFormPropertyId) {
      setMaintenanceFormError("Please choose a property.");
      return;
    }

    if (!maintenanceFormCategory.trim()) {
      setMaintenanceFormError("Please choose a category.");
      return;
    }

    if (!maintenanceFormNotes.trim()) {
      setMaintenanceFormError("Please add notes describing the issue.");
      return;
    }

    setMaintenanceFormError("");
    setError("");
    setActionMessage("");
    setCreatingMaintenanceFlag(true);

    try {
      const {
        data: { session },
      } = await supabase.auth.getSession();

      if (!session?.access_token) {
        throw new Error("Please sign in again before creating a maintenance flag.");
      }

      const response = await fetch("/api/admin/maintenance-flag", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${session.access_token}`,
        },
        body: JSON.stringify({
          organizationId: currentOrganizationId,
          propertyId: maintenanceFormPropertyId,
          category: maintenanceFormCategory.trim(),
          urgency: maintenanceFormUrgency,
          notes: maintenanceFormNotes.trim(),
        }),
      });

      const payload = await response.json().catch(() => null);

      if (!response.ok) {
        throw new Error(payload?.error || "Could not create maintenance flag.");
      }

      const flagId = String(payload?.flag?.id || "");
      const photoCount = flagId ? await uploadMaintenanceFlagImages(flagId) : 0;

      closeMaintenanceModal();
      setActionMessage(
        photoCount > 0
          ? `Maintenance flag created with ${photoCount} photo${photoCount === 1 ? "" : "s"}.`
          : "Maintenance flag created."
      );
      await loadData();
    } catch (err: any) {
      setError(err?.message || "Could not create maintenance flag.");
      await loadData();
    } finally {
      setCreatingMaintenanceFlag(false);
    }
  }

  function startEditingMaintenanceFlag(flag: MaintenanceFlagRow) {
    setEditingMaintenanceFlagId(flag.id);
    setMaintenanceEditCategory(flag.category || "");
    setMaintenanceEditUrgency(flag.urgency || flag.priority || flag.severity || "normal");
    setMaintenanceEditNotes(flag.notes || "");
    setError("");
    setActionMessage("");
  }

  function cancelEditingMaintenanceFlag() {
    setEditingMaintenanceFlagId(null);
    setMaintenanceEditCategory("");
    setMaintenanceEditUrgency("normal");
    setMaintenanceEditNotes("");
  }

  async function saveMaintenanceFlagEdit(flagId: string) {
    if (!currentOrganizationId) return;

    const category = maintenanceEditCategory.trim();
    const notes = maintenanceEditNotes.trim();

    if (!category || !notes) {
      setError("Category and notes are required before saving a maintenance flag.");
      return;
    }

    setResolvingMaintenanceFlagId(flagId);
    setError("");
    setActionMessage("");

    try {
      const {
        data: { session },
      } = await supabase.auth.getSession();

      if (!session?.access_token) {
        throw new Error("Please sign in again before editing a maintenance flag.");
      }

      const response = await fetch("/api/admin/maintenance-flag", {
        method: "PATCH",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${session.access_token}`,
        },
        body: JSON.stringify({
          action: "update",
          organizationId: currentOrganizationId,
          flagId,
          category,
          urgency: maintenanceEditUrgency,
          notes,
        }),
      });

      const payload = await response.json().catch(() => null);
      if (!response.ok) {
        throw new Error(payload?.error || "Could not update maintenance flag.");
      }

      cancelEditingMaintenanceFlag();
      setActionMessage("Maintenance flag updated.");
      await loadData();
    } catch (err: any) {
      setError(err?.message || "Could not update maintenance flag.");
    } finally {
      setResolvingMaintenanceFlagId(null);
    }
  }

  async function notifyOwnerAboutMaintenanceFlag(flagId: string) {
    if (!currentOrganizationId) return;

    setNotifyingMaintenanceOwnerId(flagId);
    setError("");
    setActionMessage("");

    try {
      const {
        data: { session },
      } = await supabase.auth.getSession();

      if (!session?.access_token) {
        throw new Error("Please sign in again before notifying an owner.");
      }

      const response = await fetch("/api/admin/maintenance-flag", {
        method: "PATCH",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${session.access_token}`,
        },
        body: JSON.stringify({
          action: "notify_owner",
          organizationId: currentOrganizationId,
          flagId,
        }),
      });

      const payload = await response.json().catch(() => null);
      if (!response.ok) {
        throw new Error(payload?.error || "Could not notify owner.");
      }

      const notified = Number(payload?.notified || 0);
      setActionMessage(`Owner notification sent to ${notified} recipient${notified === 1 ? "" : "s"}.`);
      await loadData();
    } catch (err: any) {
      setError(err?.message || "Could not notify owner.");
    } finally {
      setNotifyingMaintenanceOwnerId(null);
    }
  }

  async function resolveMaintenanceFlag(flagId: string) {
    if (!currentAdminUserId) {
      setError("Admin user not found.");
      return;
    }

    setError("");
    setActionMessage("");
    setResolvingMaintenanceFlagId(flagId);

    try {
      const {
        data: { session },
      } = await supabase.auth.getSession();

      if (!session?.access_token) {
        throw new Error("Please sign in again before resolving a maintenance flag.");
      }

      const response = await fetch("/api/admin/maintenance-flag", {
        method: "PATCH",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${session.access_token}`,
        },
        body: JSON.stringify({
          organizationId: currentOrganizationId,
          flagId,
        }),
      });

      const payload = await response.json().catch(() => null);

      if (!response.ok) {
        throw new Error(payload?.error || "Could not resolve maintenance flag.");
      }

      setActionMessage("Maintenance flag resolved.");
      unsnoozeMaintenanceFlag(flagId);
      await loadData();
    } catch (err: any) {
      setError(err?.message || "Could not resolve maintenance flag.");
    } finally {
      setResolvingMaintenanceFlagId(null);
    }
  }

  async function deleteMaintenanceFlag(flagId: string) {
    const confirmed = window.confirm("Delete this maintenance flag? This cannot be undone.");
    if (!confirmed) return;

    setError("");
    setActionMessage("");
    setDeletingMaintenanceFlagId(flagId);

    try {
      const {
        data: { session },
      } = await supabase.auth.getSession();

      if (!session?.access_token) {
        throw new Error("Please sign in again before deleting a maintenance flag.");
      }

      const response = await fetch("/api/admin/maintenance-flag", {
        method: "DELETE",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${session.access_token}`,
        },
        body: JSON.stringify({
          organizationId: currentOrganizationId,
          flagIds: [flagId],
        }),
      });

      const payload = await response.json().catch(() => null);

      if (!response.ok) {
        throw new Error(payload?.error || "Could not delete maintenance flag.");
      }

      setActionMessage("Maintenance flag deleted.");
      unsnoozeMaintenanceFlag(flagId);
      await loadData();
    } catch (err: any) {
      setError(err?.message || "Could not delete maintenance flag.");
    } finally {
      setDeletingMaintenanceFlagId(null);
    }
  }


  async function deleteResolvedMaintenanceFlags() {
    const resolvedIds = filteredMaintenanceFlags
      .filter((flag) => {
        const stateLower = String(getMaintenanceFlagState(flag) || "").toLowerCase();
        return stateLower.includes("resolved") || stateLower.includes("closed") || stateLower.includes("done");
      })
      .map((flag) => flag.id);

    if (resolvedIds.length === 0) {
      setActionMessage("No resolved maintenance flags to delete.");
      return;
    }

    const confirmed = window.confirm(
      `Delete ${resolvedIds.length} resolved maintenance flag${resolvedIds.length === 1 ? "" : "s"}? This cannot be undone.`
    );
    if (!confirmed) return;

    setError("");
    setActionMessage("");
    setDeletingResolvedMaintenanceFlags(true);

    try {
      const {
        data: { session },
      } = await supabase.auth.getSession();

      if (!session?.access_token) {
        throw new Error("Please sign in again before deleting maintenance flags.");
      }

      const response = await fetch("/api/admin/maintenance-flag", {
        method: "DELETE",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${session.access_token}`,
        },
        body: JSON.stringify({
          organizationId: currentOrganizationId,
          flagIds: resolvedIds,
        }),
      });

      const payload = await response.json().catch(() => null);

      if (!response.ok) {
        throw new Error(payload?.error || "Could not delete resolved maintenance flags.");
      }

      setActionMessage(`Deleted ${resolvedIds.length} resolved maintenance flag${resolvedIds.length === 1 ? "" : "s"}.`);
      await loadData();
    } catch (err: any) {
      setError(err?.message || "Could not delete resolved maintenance flags.");
    } finally {
      setDeletingResolvedMaintenanceFlags(false);
    }
  }

  const selectedSops = useMemo(
    () => sops.filter((x) => x.property_id === selectedPropertyId),
    [sops, selectedPropertyId]
  );
  const selectedPropertyChecklistItems = useMemo(
    () =>
      propertyCleaningChecklistItems
        .filter((item) => item.property_id === selectedPropertyId && item.active !== false)
        .sort((a, b) => a.sort_order - b.sort_order || a.title.localeCompare(b.title)),
    [propertyCleaningChecklistItems, selectedPropertyId]
  );
  const selectedPropertyVendors = useMemo(
    () => propertyVendors.filter((vendor) => vendor.property_id === selectedPropertyId),
    [propertyVendors, selectedPropertyId]
  );
  const selectedPropertyKnowledge = useMemo(
    () => propertyKnowledgeRows.find((row) => row.property_id === selectedPropertyId) || null,
    [propertyKnowledgeRows, selectedPropertyId]
  );
  const selectedPropertyKnowledgeImages = useMemo(
    () => propertyKnowledgeImages.filter((image) => image.property_id === selectedPropertyId),
    [propertyKnowledgeImages, selectedPropertyId]
  );
  const accessPropertyRows = useMemo(() => {
    return properties
      .map((property) => {
        const latitude = parseCoordinate(property.latitude);
        const longitude = parseCoordinate(property.longitude);
        const distanceMeters =
          nearbyPosition && latitude !== null && longitude !== null
            ? getDistanceMeters(nearbyPosition, { latitude, longitude })
            : null;

        return {
          property,
          latitude,
          longitude,
          distanceMeters,
          access: accessRows.find((row) => row.property_id === property.id) || null,
          knowledge: propertyKnowledgeRows.find((row) => row.property_id === property.id) || null,
          openFlagCount: maintenanceFlags.filter(
            (flag) => flag.property_id === property.id && !isMaintenanceFlagResolved(flag)
          ).length,
        };
      })
      .sort((a, b) => {
        if (a.distanceMeters !== null && b.distanceMeters !== null) {
          return a.distanceMeters - b.distanceMeters;
        }
        if (a.distanceMeters !== null) return -1;
        if (b.distanceMeters !== null) return 1;
        return (a.property.name || a.property.address || "").localeCompare(
          b.property.name || b.property.address || ""
        );
      });
  }, [properties, accessRows, propertyKnowledgeRows, maintenanceFlags, nearbyPosition]);

  const nearbyPropertyRows = useMemo(() => {
    const search = nearbySearch.trim().toLowerCase();
    if (!search) return accessPropertyRows;

    return accessPropertyRows.filter((row) =>
      [
        row.property.name,
        row.property.address,
        row.access?.door_code,
        row.access?.notes,
        row.knowledge?.access_summary,
        row.knowledge?.lockbox_location,
      ]
        .filter(Boolean)
        .join(" ")
        .toLowerCase()
        .includes(search)
    );
  }, [accessPropertyRows, nearbySearch]);

  const nearbyDetectedRows = useMemo(
    () =>
      accessPropertyRows.filter(
        (row) => row.distanceMeters !== null && row.distanceMeters <= 250
      ),
    [accessPropertyRows]
  );

  const closestNearbyPropertyRow = nearbyDetectedRows[0] || null;

  const maintenanceImagesByFlagId = useMemo(() => {
    const map: Record<string, MaintenanceFlagImageRow[]> = {};
    for (const image of maintenanceFlagImages) {
      if (!map[image.flag_id]) map[image.flag_id] = [];
      map[image.flag_id].push(image);
    }
    for (const key of Object.keys(map)) {
      map[key].sort((a, b) => a.sort_order - b.sort_order);
    }
    return map;
  }, [maintenanceFlagImages]);

  const sopImagesBySopId = useMemo(() => {
    const map: Record<string, SopImageRow[]> = {};
    for (const image of sopImages) {
      if (!map[image.sop_id]) map[image.sop_id] = [];
      map[image.sop_id].push(image);
    }
    return map;
  }, [sopImages]);

  const jobSlotsByJobId = useMemo(() => {
    const map: Record<string, JobSlot[]> = {};
    for (const slot of jobSlots) {
      if (!map[slot.job_id]) map[slot.job_id] = [];
      map[slot.job_id].push(slot);
    }
    for (const key of Object.keys(map)) {
      map[key].sort((a, b) => a.slot_number - b.slot_number);
    }
    return map;
  }, [jobSlots]);

  const turnoverChecklistItemsByJobId = useMemo(() => {
    const map: Record<string, TurnoverJobChecklistItemRow[]> = {};
    for (const item of turnoverJobChecklistItems) {
      if (!map[item.job_id]) map[item.job_id] = [];
      map[item.job_id].push(item);
    }
    for (const key of Object.keys(map)) {
      map[key].sort((a, b) => a.sort_order - b.sort_order || a.title.localeCompare(b.title));
    }
    return map;
  }, [turnoverJobChecklistItems]);

  const staffJobStatusEventsByJobId = useMemo(() => {
    const map: Record<string, StaffJobStatusEventRow[]> = {};
    for (const event of staffJobStatusEvents) {
      if (!map[event.job_id]) map[event.job_id] = [];
      map[event.job_id].push(event);
    }
    for (const key of Object.keys(map)) {
      map[key].sort((a, b) => new Date(b.created_at || 0).getTime() - new Date(a.created_at || 0).getTime());
    }
    return map;
  }, [staffJobStatusEvents]);

  const groundsJobSlotsByJobId = useMemo(() => {
    const map: Record<string, GroundsJobSlot[]> = {};
    for (const slot of groundsJobSlots) {
      if (!map[slot.job_id]) map[slot.job_id] = [];
      map[slot.job_id].push(slot);
    }
    for (const key of Object.keys(map)) {
      map[key].sort((a, b) => a.slot_number - b.slot_number);
    }
    return map;
  }, [groundsJobSlots]);

  const cleanerMembersByAccountId = useMemo(() => {
    const map: Record<string, ProfileRow[]> = {};
    for (const member of cleanerAccountMembers) {
      const profile = profiles.find((p) => p.id === member.profile_id);
      if (!profile) continue;
      if (!map[member.cleaner_account_id]) map[member.cleaner_account_id] = [];
      map[member.cleaner_account_id].push(profile);
    }
    return map;
  }, [cleanerAccountMembers, profiles]);

  const groundsMembersByAccountId = useMemo(() => {
    const map: Record<string, ProfileRow[]> = {};
    for (const member of groundsAccountMembers) {
      const profile = profiles.find((p) => p.id === member.profile_id);
      if (!profile) continue;
      if (!map[member.grounds_account_id]) map[member.grounds_account_id] = [];
      map[member.grounds_account_id].push(profile);
    }
    return map;
  }, [groundsAccountMembers, profiles]);

  const cleanerAccountNamesByProfileId = useMemo(() => {
    const map: Record<string, string[]> = {};
    for (const member of cleanerAccountMembers) {
      const label =
        cleanerAccounts.find((account) => account.id === member.cleaner_account_id)?.display_name ||
        member.cleaner_account_id;
      if (!map[member.profile_id]) map[member.profile_id] = [];
      if (!map[member.profile_id].includes(label)) map[member.profile_id].push(label);
    }
    return map;
  }, [cleanerAccountMembers, cleanerAccounts]);

  const groundsAccountNamesByProfileId = useMemo(() => {
    const map: Record<string, string[]> = {};
    for (const member of groundsAccountMembers) {
      const label =
        groundsAccounts.find((account) => account.id === member.grounds_account_id)?.display_name ||
        member.grounds_account_id;
      if (!map[member.profile_id]) map[member.profile_id] = [];
      if (!map[member.profile_id].includes(label)) map[member.profile_id].push(label);
    }
    return map;
  }, [groundsAccountMembers, groundsAccounts]);

  const eligibleCleanerProfiles = useMemo(
    () => profiles.filter((profile) => profile.role === "cleaner"),
    [profiles]
  );

  const assignableCleanerAccounts = useMemo(
    () =>
      cleanerAccounts
        .filter((account) => account.active !== false)
        .sort((a, b) =>
          (a.display_name || a.email || "").localeCompare(b.display_name || b.email || "")
        ),
    [cleanerAccounts]
  );

  const currentAdminCleanerAccountIds = useMemo(() => {
    if (!currentAdminProfile?.id) return new Set<string>();
    const accountIds = cleanerAccountMembers
      .filter((member) => member.profile_id === currentAdminProfile.id)
      .map((member) => member.cleaner_account_id)
      .filter(Boolean);
    return new Set(accountIds);
  }, [cleanerAccountMembers, currentAdminProfile]);

  const currentAdminCleanerAccounts = useMemo(
    () => cleanerAccounts.filter((account) => currentAdminCleanerAccountIds.has(account.id)),
    [cleanerAccounts, currentAdminCleanerAccountIds]
  );

  const eligibleGroundsProfiles = useMemo(
    () => profiles.filter((profile) => profile.role === "grounds" || profile.role === "cleaner"),
    [profiles]
  );

  const teamAvailabilityRows = useMemo(() => {
    const windowEnd = new Date(now);
    windowEnd.setDate(windowEnd.getDate() + 14);
    const windowEndYmd = toYmd(windowEnd);
    const rows: Array<{
      id: string;
      kind: "Cleaner" | "Grounds";
      name: string;
      members: string;
      active: boolean;
      todayCount: number;
      upcomingCount: number;
      pendingOffers: number;
      nextJobDate: string | null;
      status: "Available" | "Busy today" | "Booked soon" | "Needs response" | "Inactive";
      tone: string;
    }> = [];

    for (const account of cleanerAccounts) {
      const accountSlots = jobSlots.filter((slot) => slot.cleaner_account_id === account.id);
      const relevantSlots = accountSlots.filter((slot) => {
        const job = jobs.find((entry) => entry.id === slot.job_id);
        const jobDate = job?.scheduled_for || extractCheckoutDate(job?.notes || null);
        return !!jobDate && jobDate >= todayYmd && jobDate <= windowEndYmd && slot.status !== "declined";
      });
      const dates = relevantSlots
        .map((slot) => {
          const job = jobs.find((entry) => entry.id === slot.job_id);
          return job?.scheduled_for || extractCheckoutDate(job?.notes || null);
        })
        .filter((value): value is string => !!value)
        .sort();
      const todayCount = dates.filter((date) => date === todayYmd).length;
      const pendingOffers = relevantSlots.filter((slot) => slot.status === "offered").length;
      const members = cleanerMembersByAccountId[account.id] ?? [];
      let status: "Available" | "Busy today" | "Booked soon" | "Needs response" | "Inactive" = "Available";
      if (account.active === false) status = "Inactive";
      else if (pendingOffers > 0) status = "Needs response";
      else if (todayCount > 0) status = "Busy today";
      else if (dates.length > 0) status = "Booked soon";

      rows.push({
        id: `cleaner-${account.id}`,
        kind: "Cleaner",
        name: account.display_name || account.email || "Cleaner account",
        members: members.length ? members.map((member) => member.full_name || member.email || member.id).join(", ") : account.email || "No linked members",
        active: account.active !== false,
        todayCount,
        upcomingCount: dates.length,
        pendingOffers,
        nextJobDate: dates[0] || null,
        status,
        tone:
          status === "Available"
            ? "border-[#bbdfc0] bg-[#f0fbf2] text-[#236b30]"
            : status === "Needs response"
              ? "border-[#f0b4b4] bg-[#fff5f5] text-[#8a2e22]"
              : status === "Inactive"
                ? "border-[#d8c7ab] bg-[#f6f2eb] text-[#6f6255]"
                : "border-[#f1cf8f] bg-[#fff8e8] text-[#8a6112]",
      });
    }

    for (const account of groundsAccounts) {
      const accountSlots = groundsJobSlots.filter((slot) => slot.grounds_account_id === account.id);
      const relevantSlots = accountSlots.filter((slot) => {
        const job = groundsJobs.find((entry) => entry.id === slot.job_id);
        const jobDate = job?.scheduled_for || null;
        return !!jobDate && jobDate >= todayYmd && jobDate <= windowEndYmd && slot.status !== "declined";
      });
      const dates = relevantSlots
        .map((slot) => groundsJobs.find((entry) => entry.id === slot.job_id)?.scheduled_for || null)
        .filter((value): value is string => !!value)
        .sort();
      const todayCount = dates.filter((date) => date === todayYmd).length;
      const pendingOffers = relevantSlots.filter((slot) => slot.status === "offered").length;
      const members = groundsMembersByAccountId[account.id] ?? [];
      let status: "Available" | "Busy today" | "Booked soon" | "Needs response" | "Inactive" = "Available";
      if (account.active === false) status = "Inactive";
      else if (pendingOffers > 0) status = "Needs response";
      else if (todayCount > 0) status = "Busy today";
      else if (dates.length > 0) status = "Booked soon";

      rows.push({
        id: `grounds-${account.id}`,
        kind: "Grounds",
        name: account.display_name || account.email || "Grounds account",
        members: members.length ? members.map((member) => member.full_name || member.email || member.id).join(", ") : account.email || "No linked members",
        active: account.active !== false,
        todayCount,
        upcomingCount: dates.length,
        pendingOffers,
        nextJobDate: dates[0] || null,
        status,
        tone:
          status === "Available"
            ? "border-[#bbdfc0] bg-[#f0fbf2] text-[#236b30]"
            : status === "Needs response"
              ? "border-[#f0b4b4] bg-[#fff5f5] text-[#8a2e22]"
              : status === "Inactive"
                ? "border-[#d8c7ab] bg-[#f6f2eb] text-[#6f6255]"
                : "border-[#f1cf8f] bg-[#fff8e8] text-[#8a6112]",
      });
    }

    return rows.sort((a, b) => {
      const order = ["Needs response", "Busy today", "Booked soon", "Available", "Inactive"];
      const statusDiff = order.indexOf(a.status) - order.indexOf(b.status);
      if (statusDiff !== 0) return statusDiff;
      return a.name.localeCompare(b.name);
    });
  }, [
    cleanerAccounts,
    groundsAccounts,
    jobSlots,
    groundsJobSlots,
    jobs,
    groundsJobs,
    todayYmd,
    now,
    cleanerMembersByAccountId,
    groundsMembersByAccountId,
  ]);

  const teamAvailabilityStats = useMemo(() => {
    const available = teamAvailabilityRows.filter((row) => row.status === "Available").length;
    const busyToday = teamAvailabilityRows.filter((row) => row.status === "Busy today").length;
    const needsResponse = teamAvailabilityRows.filter((row) => row.status === "Needs response").length;
    const bookedSoon = teamAvailabilityRows.filter((row) => row.status === "Booked soon").length;

    return {
      total: teamAvailabilityRows.length,
      available,
      busyToday,
      needsResponse,
      bookedSoon,
    };
  }, [teamAvailabilityRows]);

  function getActiveCountdownMs(jobId: string) {
    const slots = jobSlotsByJobId[jobId] ?? [];
    const activeOffered = slots
      .filter((slot) => slot.status === "offered" && !!slot.expires_at)
      .sort((a, b) => new Date(a.expires_at || 0).getTime() - new Date(b.expires_at || 0).getTime());

    if (!activeOffered.length || !activeOffered[0].expires_at) return null;
    return new Date(activeOffered[0].expires_at).getTime() - now.getTime();
  }

  function getJobDisplayStatus(job: Job, slots: JobSlot[]) {
    const needed = job.cleaner_units_needed || Math.max(slots.length, 1);
    const accepted = slots.filter((slot) =>
      ["accepted", "in_progress", "completed"].includes(String(slot.status || "").toLowerCase())
    ).length;
    const offered = slots.filter((slot) => slot.status === "offered").length;
    const declined = slots.filter((slot) => slot.status === "declined").length;
    const stranded = slots.filter((slot) => slot.status === "stranded").length;

    if (accepted >= needed) return "Fully staffed";
    if (accepted > 0 && job.cleaner_units_required_strict) return "Partially filled";
    if (accepted > 0 && !job.cleaner_units_required_strict) return "Ready";
    if (stranded > 0 || job.staffing_status === "stranded") return "Stranded";
    if (offered > 0) return "Jobs waiting for acceptance";
    if (declined > 0) return "Reoffer needed";
    return job.staffing_status || job.status || "Unknown";
  }

  function isJobWaitingForAcceptance(job: Job, slots: JobSlot[]) {
    const offered = slots.filter((slot) => slot.status === "offered").length;
    if (offered === 0) return false;

    const acceptedLike = slots.filter((slot) =>
      ["accepted", "in_progress", "completed"].includes(String(slot.status || "").toLowerCase())
    ).length;
    const needed = job.cleaner_units_needed || Math.max(slots.length, 1);

    return job.cleaner_units_required_strict ? acceptedLike < needed : acceptedLike === 0;
  }

  const waitingJobs = useMemo(
    () =>
      jobs.filter((job) => isJobWaitingForAcceptance(job, jobSlotsByJobId[job.id] ?? [])),
    [jobs, jobSlotsByJobId]
  );

  const overdueWaitingJobs = useMemo(
    () =>
      waitingJobs.filter((job) => {
        const slots = jobSlotsByJobId[job.id] ?? [];
        const firstOffered = slots
          .filter((slot) => slot.status === "offered")
          .sort(
            (a, b) =>
              new Date(a.offered_at || 0).getTime() - new Date(b.offered_at || 0).getTime()
          )[0];

        const remainingMs = getTimeRemainingMs(job, firstOffered?.offered_at, now);
        return remainingMs !== null && remainingMs < 0;
      }),
    [waitingJobs, jobSlotsByJobId, now]
  );

  function jumpToJobs(type: "waiting" | "stranded") {
    setActiveSection("jobs");
    setJobWorkflowTab(type === "waiting" ? "active" : "exceptions");
    if (type === "waiting") {
      setSelectedJobsPropertyFilter("all");
      setJobsExpanded(true);
      setHighlightedJobId(waitingJobs[0]?.id || null);
    }

    setTimeout(() => {
      if (type === "waiting" && waitingJobs[0]?.id) {
        document
          .getElementById(`job-${waitingJobs[0].id}`)
          ?.scrollIntoView({ behavior: "smooth", block: "center" });
        return;
      }

      document
        .getElementById(
          type === "waiting" ? "waiting-jobs-section" : "stranded-jobs-section"
        )
        ?.scrollIntoView({ behavior: "smooth", block: "start" });
    }, 50);
  }
  const filteredJobs = useMemo(
    () => {
      const scopedJobs =
        selectedJobsPropertyFilter === "all"
          ? jobs
          : jobs.filter((job) => job.property_id === selectedJobsPropertyFilter);

      return [...scopedJobs].sort((a, b) => {
        const aSlots = jobSlotsByJobId[a.id] ?? [];
        const bSlots = jobSlotsByJobId[b.id] ?? [];
        const aWaiting = aSlots.some((slot) => slot.status === "offered");
        const bWaiting = bSlots.some((slot) => slot.status === "offered");
        if (aWaiting !== bWaiting) return aWaiting ? -1 : 1;

        const aStranded = aSlots.some((slot) => slot.status === "stranded" || !slot.cleaner_account_id);
        const bStranded = bSlots.some((slot) => slot.status === "stranded" || !slot.cleaner_account_id);
        if (aStranded !== bStranded) return aStranded ? -1 : 1;

        const aDate = a.scheduled_for || extractCheckoutDate(a.notes) || "";
        const bDate = b.scheduled_for || extractCheckoutDate(b.notes) || "";
        return aDate.localeCompare(bDate) || (b.created_at || "").localeCompare(a.created_at || "");
      });
    },
    [jobs, selectedJobsPropertyFilter, jobSlotsByJobId]
  );

  const visibleJobs = jobsExpanded ? filteredJobs : filteredJobs.slice(0, 3);

  const jobReliabilityRows = useMemo(() => {
    const rows: Array<{
      id: string;
      kind: "Cleaner" | "Grounds";
      kindApi: "cleaner" | "grounds";
      slotId: string;
      propertyName: string;
      accountName: string;
      scheduledFor: string | null | undefined;
      status: string;
      notificationLabel: string;
      notificationTone: string;
      offerEmailSentAt?: string | null;
      offerPushSentAt?: string | null;
      offeredAt?: string | null;
      expiresAt?: string | null;
      acceptedAt?: string | null;
      declinedAt?: string | null;
      overdue: boolean;
    }> = [];

    for (const job of jobs) {
      if (selectedJobsPropertyFilter !== "all" && job.property_id !== selectedJobsPropertyFilter) continue;
      const slots = jobSlotsByJobId[job.id] ?? [];
      for (const slot of slots) {
        const expiresAt = slot.expires_at ? new Date(slot.expires_at) : null;
        rows.push({
          id: `cleaner-${slot.id}`,
          kind: "Cleaner",
          kindApi: "cleaner",
          slotId: slot.id,
          propertyName: getPropertyName(job.property_id),
          accountName: getCleanerAccountName(slot.cleaner_account_id),
          scheduledFor: job.scheduled_for || extractCheckoutDate(job.notes),
          status: slot.status,
          notificationLabel: getJobNotificationLabel(slot),
          notificationTone: getJobNotificationTone(slot),
          offerEmailSentAt: slot.offer_email_sent_at,
          offerPushSentAt: slot.offer_push_sent_at,
          offeredAt: slot.offered_at,
          expiresAt: slot.expires_at,
          acceptedAt: slot.accepted_at,
          declinedAt: slot.declined_at,
          overdue: slot.status === "offered" && !!expiresAt && expiresAt.getTime() < now.getTime(),
        });
      }
    }

    for (const job of groundsJobs) {
      if (selectedJobsPropertyFilter !== "all" && job.property_id !== selectedJobsPropertyFilter) continue;
      const slots = groundsJobSlotsByJobId[job.id] ?? [];
      for (const slot of slots) {
        const expiresAt = slot.expires_at ? new Date(slot.expires_at) : null;
        rows.push({
          id: `grounds-${slot.id}`,
          kind: "Grounds",
          kindApi: "grounds",
          slotId: slot.id,
          propertyName: getPropertyName(job.property_id),
          accountName: getGroundsAccountName(slot.grounds_account_id),
          scheduledFor: job.scheduled_for,
          status: slot.status,
          notificationLabel: getJobNotificationLabel(slot),
          notificationTone: getJobNotificationTone(slot),
          offerEmailSentAt: slot.offer_email_sent_at,
          offerPushSentAt: slot.offer_push_sent_at,
          offeredAt: slot.offered_at,
          expiresAt: slot.expires_at,
          acceptedAt: slot.accepted_at,
          declinedAt: slot.declined_at,
          overdue: slot.status === "offered" && !!expiresAt && expiresAt.getTime() < now.getTime(),
        });
      }
    }

    return rows.sort((a, b) => {
      const aNeedsAttention = (a.status === "offered" && (!a.offerEmailSentAt || !a.offerPushSentAt)) || a.overdue || a.status === "declined";
      const bNeedsAttention = (b.status === "offered" && (!b.offerEmailSentAt || !b.offerPushSentAt)) || b.overdue || b.status === "declined";
      if (aNeedsAttention !== bNeedsAttention) return aNeedsAttention ? -1 : 1;
      return new Date(b.offeredAt || b.acceptedAt || b.declinedAt || 0).getTime() - new Date(a.offeredAt || a.acceptedAt || a.declinedAt || 0).getTime();
    });
  }, [jobs, groundsJobs, selectedJobsPropertyFilter, jobSlotsByJobId, groundsJobSlotsByJobId, now]);

  const jobReliabilityStats = useMemo(() => {
    const total = jobReliabilityRows.length;
    const accepted = jobReliabilityRows.filter((row) => row.status === "accepted").length;
    const waiting = jobReliabilityRows.filter((row) => row.status === "offered").length;
    const overdue = jobReliabilityRows.filter((row) => row.overdue).length;
    const declined = jobReliabilityRows.filter((row) => row.status === "declined").length;
    const emailPending = jobReliabilityRows.filter((row) => row.status === "offered" && !row.offerEmailSentAt).length;
    const pushPending = jobReliabilityRows.filter((row) => row.status === "offered" && !row.offerPushSentAt).length;

    return {
      total,
      accepted,
      waiting,
      overdue,
      declined,
      emailPending,
      pushPending,
      acceptedRate: total > 0 ? Math.round((accepted / total) * 100) : 0,
    };
  }, [jobReliabilityRows]);

  const failedNotificationRows = useMemo(
    () =>
      jobReliabilityRows.filter(
        (row) =>
          row.status === "offered" &&
          (!row.offerEmailSentAt || !row.offerPushSentAt || row.overdue)
      ),
    [jobReliabilityRows]
  );

  const failedNotificationStats = useMemo(() => {
    const overdue = failedNotificationRows.filter((row) => row.overdue).length;
    const cleaner = failedNotificationRows.filter((row) => row.kindApi === "cleaner").length;
    const grounds = failedNotificationRows.filter((row) => row.kindApi === "grounds").length;

    return {
      total: failedNotificationRows.length,
      overdue,
      cleaner,
      grounds,
    };
  }, [failedNotificationRows]);

  const recentDeclinedJobs = useMemo(
    () =>
      [...jobSlots]
        .filter((slot) => !!slot.declined_at)
        .filter((slot) => {
          if (selectedJobsPropertyFilter === "all") return true
          const matchingJob = jobs.find((job) => job.id === slot.job_id)
          return matchingJob?.property_id === selectedJobsPropertyFilter
        })
        .sort((a, b) => new Date(b.declined_at || 0).getTime() - new Date(a.declined_at || 0).getTime())
        .slice(0, 10),
    [jobSlots, jobs, selectedJobsPropertyFilter]
  );

  const recentCleanerArrivalEvents = useMemo(
    () =>
      staffJobStatusEvents
        .filter((event) => event.job_kind === "cleaner" && event.event_type === "arrived")
        .filter((event) => {
          if (selectedJobsPropertyFilter === "all") return true;
          const propertyId = String(event.metadata?.property_id || "");
          return propertyId === selectedJobsPropertyFilter;
        })
        .sort((a, b) => new Date(b.created_at || 0).getTime() - new Date(a.created_at || 0).getTime())
        .slice(0, 8),
    [staffJobStatusEvents, selectedJobsPropertyFilter]
  );

  const filteredStrandedJobs = useMemo(
    () =>
      selectedJobsPropertyFilter === "all"
        ? strandedJobs
        : strandedJobs.filter((job) => job.property_id === selectedJobsPropertyFilter),
    [strandedJobs, selectedJobsPropertyFilter]
  );

  const adminJobsByDate = useMemo(() => {
    const map = new Map<string, Job[]>();

    for (const job of jobs) {
      const jobDate = job.scheduled_for || extractCheckoutDate(job.notes);
      if (!jobDate) continue;
      if (!map.has(jobDate)) map.set(jobDate, []);
      map.get(jobDate)!.push(job);
    }

    for (const [key, value] of map.entries()) {
      value.sort((a, b) => {
        const aName = getPropertyName(a.property_id);
        const bName = getPropertyName(b.property_id);
        return aName.localeCompare(bName);
      });
      map.set(key, value);
    }

    return map;
  }, [jobs, properties]);

  const adminBookingEventsByDate = useMemo(() => {
    const map = new Map<string, PropertyBookingEvent[]>();

    for (const booking of propertyBookingEvents) {
      if (!booking.checkin_date) continue;
      if (!map.has(booking.checkin_date)) map.set(booking.checkin_date, []);
      map.get(booking.checkin_date)!.push(booking);
    }

    for (const [key, value] of map.entries()) {
      value.sort((a, b) => {
        const aName = getPropertyName(a.property_id);
        const bName = getPropertyName(b.property_id);
        return aName.localeCompare(bName);
      });
      map.set(key, value);
    }

    return map;
  }, [propertyBookingEvents, properties]);

  const adminCalendarDays = useMemo(() => getMonthGrid(adminCalendarMonth), [adminCalendarMonth]);

  const adminSelectedDayJobs = useMemo(() => {
    if (!adminSelectedDate) return [];
    const dayJobs = adminJobsByDate.get(adminSelectedDate) ?? [];
    return selectedJobsPropertyFilter === "all"
      ? dayJobs
      : dayJobs.filter((job) => job.property_id === selectedJobsPropertyFilter);
  }, [adminJobsByDate, adminSelectedDate, selectedJobsPropertyFilter]);

  const adminSelectedDayBookingEvents = useMemo(() => {
    if (!adminSelectedDate) return [];
    const dayBookings = adminBookingEventsByDate.get(adminSelectedDate) ?? [];
    return selectedJobsPropertyFilter === "all"
      ? dayBookings
      : dayBookings.filter((booking) => booking.property_id === selectedJobsPropertyFilter);
  }, [adminBookingEventsByDate, adminSelectedDate, selectedJobsPropertyFilter]);

  const filteredMaintenanceFlags = useMemo(() => {
    const filteredByProperty =
      selectedJobsPropertyFilter === "all"
        ? maintenanceFlags
        : maintenanceFlags.filter((flag) => flag.property_id === selectedJobsPropertyFilter);

    return [...filteredByProperty].sort(
      (a, b) => new Date(b.updated_at || b.created_at || 0).getTime() - new Date(a.updated_at || a.created_at || 0).getTime()
    );
  }, [maintenanceFlags, selectedJobsPropertyFilter]);

  const maintenanceFlagCounts = useMemo(() => {
    let open = 0;
    let resolved = 0;
    let urgent = 0;

    for (const flag of filteredMaintenanceFlags) {
      const urgency = String(flag.urgency || flag.priority || flag.severity || "").toLowerCase();
      const isResolved = isMaintenanceFlagResolved(flag);
      const isSnoozed = isMaintenanceFlagSnoozed(flag);
      const isUrgent = urgency.includes("high") || urgency.includes("urgent") || urgency.includes("critical");

      if (isResolved) {
        resolved += 1;
      } else if (!isSnoozed) {
        open += 1;
        if (isUrgent) urgent += 1;
      }
    }

    return {
      total: filteredMaintenanceFlags.length,
      open,
      resolved,
      urgent,
    };
  }, [filteredMaintenanceFlags, maintenanceFlagSnoozes, now]);

  const openMaintenanceFlags = useMemo(
    () =>
      filteredMaintenanceFlags.filter((flag) => {
        return !isMaintenanceFlagResolved(flag) && !isMaintenanceFlagSnoozed(flag);
      }),
    [filteredMaintenanceFlags, maintenanceFlagSnoozes, now]
  );

  const snoozedMaintenanceFlags = useMemo(
    () => filteredMaintenanceFlags.filter((flag) => isMaintenanceFlagSnoozed(flag)),
    [filteredMaintenanceFlags, maintenanceFlagSnoozes, now]
  );


  function getCleaningProgressSummary(jobId: string, slots: JobSlot[]) {
    const checklistItems = turnoverChecklistItemsByJobId[jobId] ?? [];
    const completedChecklistCount = checklistItems.filter((item) => !!item.completed_at).length;
    const latestEvents = staffJobStatusEventsByJobId[jobId] ?? [];
    const hasArrived = latestEvents.some((event) => event.job_kind === "cleaner" && event.event_type === "arrived");
    const hasStarted =
      latestEvents.some((event) => event.job_kind === "cleaner" && event.event_type === "started") ||
      slots.some((slot) => slot.status === "in_progress");
    const hasCompleted =
      latestEvents.some((event) => event.job_kind === "cleaner" && event.event_type === "completed") ||
      slots.some((slot) => slot.status === "completed");

    const parts: string[] = [];
    if (hasCompleted) parts.push("Completed");
    else if (hasStarted) parts.push("Started");
    else if (hasArrived) parts.push("Arrived");

    if (checklistItems.length > 0) {
      parts.push(`Checklist ${completedChecklistCount}/${checklistItems.length}`);
    }
    const phasePercent = hasCompleted ? 100 : hasStarted ? 66 : hasArrived ? 33 : 0;
    const checklistPercent =
      checklistItems.length > 0 ? Math.round((completedChecklistCount / checklistItems.length) * 100) : phasePercent;

    return {
      summary: parts.join(" - "),
      hasArrived,
      hasStarted,
      hasCompleted,
      checklistTotal: checklistItems.length,
      checklistCompleted: completedChecklistCount,
      progressPercent: Math.max(0, Math.min(100, checklistPercent)),
    };
  }

  function toggleTodayProgress(id: string) {
    setExpandedTodayProgressIds((current) => {
      const next = new Set(current);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  }

  function renderTodayProgress(item: {
    id: string;
    kind: string;
    progressSummary: string;
    progressCompleted: number;
    progressTotal: number;
    progressPercent: number;
  }) {
    if (item.kind !== "Cleaning") return null;

    const expanded = expandedTodayProgressIds.has(item.id);
    const label =
      item.progressTotal > 0
        ? `${item.progressCompleted}/${item.progressTotal}`
        : item.progressSummary || `${item.progressPercent}%`;

    return (
      <button
        type="button"
        onClick={() => toggleTodayProgress(item.id)}
        className="mt-2 block w-full rounded-xl border border-[#eadfce] bg-[#fffdf9] px-3 py-2 text-left transition hover:border-[#d8c7ab] hover:bg-white"
        aria-expanded={expanded}
      >
        <div className="flex items-center justify-between gap-3">
          <div className="h-2 min-w-0 flex-1 overflow-hidden rounded-full bg-[#f0e7d8]">
            <div
              className="h-full rounded-full bg-[#2f7d4f] transition-all"
              style={{ width: `${item.progressPercent}%` }}
            />
          </div>
          <span className="shrink-0 text-[11px] font-semibold uppercase tracking-[0.12em] text-[#6f6255]">
            {expanded ? "Hide" : label}
          </span>
        </div>
        {expanded ? (
          <div className="mt-2 text-xs font-medium text-[#5f5245]">
            {item.progressSummary || "No cleaner progress has been recorded yet."}
          </div>
        ) : null}
      </button>
    );
  }

  const todayAtGlanceItems = useMemo(() => {
    const propertyById = new Map(properties.map((property) => [property.id, property]));
    const getCleanerContact = (cleanerAccountId: string | null): StaffContact | null => {
      if (!cleanerAccountId) return null;
      const account = cleanerAccounts.find((item) => item.id === cleanerAccountId);
      const member = (cleanerMembersByAccountId[cleanerAccountId] ?? [])[0];
      const label = account?.display_name || member?.full_name || account?.email || member?.email || getCleanerAccountName(cleanerAccountId);
      const name = label.includes("@") ? label.split("@")[0] : label;
      if (!name) return null;
      return {
        id: `cleaner-${cleanerAccountId}`,
        kind: "Cleaner",
        name,
        email: account?.email || member?.email || null,
        phone: account?.phone || member?.phone || null,
      };
    };
    const getGroundsContact = (groundsAccountId: string | null): StaffContact | null => {
      if (!groundsAccountId) return null;
      const account = groundsAccounts.find((item) => item.id === groundsAccountId);
      const member = (groundsMembersByAccountId[groundsAccountId] ?? [])[0];
      const label = account?.display_name || member?.full_name || account?.email || member?.email || getGroundsAccountName(groundsAccountId);
      const name = label.includes("@") ? label.split("@")[0] : label;
      if (!name) return null;
      return {
        id: `grounds-${groundsAccountId}`,
        kind: "Grounds",
        name,
        email: account?.email || member?.email || null,
        phone: account?.phone || member?.phone || null,
      };
    };

    const cleaningItems = jobs
      .filter((job) => {
        const jobDate = job.scheduled_for || extractCheckoutDate(job.notes);
        return jobDate === todayYmd;
      })
      .map((job) => {
        const property = propertyById.get(job.property_id) || null;
        const slots = jobSlotsByJobId[job.id] ?? [];
        const waiting = slots.some((slot) => slot.status === "offered" || slot.status === "stranded");
        const acceptedCleanerContacts = slots
          .filter((slot) => ["accepted", "in_progress", "completed"].includes(slot.status))
          .map((slot) => getCleanerContact(slot.cleaner_account_id))
          .filter((contact): contact is StaffContact => !!contact);
        const acceptedCleanerNames = acceptedCleanerContacts.map((contact) => contact.name);
        const stranded = slots.some((slot) => slot.status === "stranded" || !slot.cleaner_account_id);
        const progress = getCleaningProgressSummary(job.id, slots);
        const cleaningStatus = acceptedCleanerNames.length > 0
          ? acceptedCleanerNames.join(", ")
          : stranded
            ? "UNASSIGNED"
            : waiting
              ? "WAITING"
              : "UNASSIGNED";
        return {
          id: `cleaning-${job.id}`,
          date: todayYmd,
          sortDate: `${todayYmd}T09:00:00`,
          kind: "Cleaning",
          title: "Cleaning",
          propertyName: property?.name || getPropertyName(job.property_id),
          city: getCityFromAddress(property?.address),
          status: cleaningStatus,
          progressSummary: progress.summary,
          progressCompleted: progress.checklistCompleted,
          progressTotal: progress.checklistTotal,
          progressPercent: progress.progressPercent,
          staffContacts: acceptedCleanerContacts,
          staffDetailLabel: "Cleaner",
          needsAttention: acceptedCleanerNames.length === 0,
        };
      });

    const groundsItems = groundsJobs
      .filter((job) => job.scheduled_for === todayYmd)
      .map((job) => {
        const property = propertyById.get(job.property_id) || null;
        const slots = groundsJobSlots.filter((slot) => slot.job_id === job.id);
        const acceptedGroundsContacts = slots
          .filter((slot) => slot.status === "accepted")
          .map((slot) => getGroundsContact(slot.grounds_account_id))
          .filter((contact): contact is StaffContact => !!contact);
        return {
          id: `grounds-${job.id}`,
          date: todayYmd,
          sortDate: `${todayYmd}T12:00:00`,
          kind: "Grounds",
          title:
            GROUNDS_JOB_TYPE_OPTIONS.find((option) => option.value === job.job_type)?.label ||
            job.job_type ||
            "Grounds job",
          propertyName: property?.name || getPropertyName(job.property_id),
          city: getCityFromAddress(property?.address),
          status: acceptedGroundsContacts.length > 0
            ? acceptedGroundsContacts.map((contact) => contact.name).join(", ")
            : getGroundsJobDisplayStatus(job, slots),
          progressSummary: "",
          progressCompleted: 0,
          progressTotal: 0,
          progressPercent: 0,
          staffContacts: acceptedGroundsContacts,
          staffDetailLabel: "Grounds",
          needsAttention: false,
        };
      });

    return [...cleaningItems, ...groundsItems].sort((a, b) =>
      a.sortDate.localeCompare(b.sortDate) || a.propertyName.localeCompare(b.propertyName)
    );
  }, [jobs, groundsJobs, properties, todayYmd, jobSlotsByJobId, turnoverChecklistItemsByJobId, staffJobStatusEventsByJobId, groundsJobSlots, cleanerAccounts, cleanerMembersByAccountId, groundsAccounts, groundsMembersByAccountId]);

  const occupiedTodayProperties = useMemo(() => {
    const propertyById = new Map(properties.map((property) => [property.id, property]));
    return propertyBookingEvents
      .filter((event) => event.checkin_date <= todayYmd && event.checkout_date > todayYmd)
      .map((event) => {
        const property = propertyById.get(event.property_id) || null;
        const guestCount = Number.isFinite(Number(event.guest_count)) ? Number(event.guest_count) : null;
        const missingBookingFields = [
          event.summary?.trim() ? "" : "guest name",
          guestCount === null ? "guest count" : "",
        ].filter(Boolean);
        return {
          id: event.id,
          propertyName: property?.name || property?.address || "Unknown property",
          city: getCityFromAddress(property?.address),
          source: getBookingSourceLabel(event.source),
          summary: event.summary || "Reserved",
          guestName: event.summary?.trim() || "",
          guestCount,
          missingBookingFields,
          checkinDate: event.checkin_date,
          checkoutDate: event.checkout_date,
          checkoutTime: formatTimeLabel(property?.default_checkout_time),
          adminNote: event.admin_note?.trim() || "",
          adminNoteImportant: Boolean(event.admin_note_important),
        };
      })
      .sort((a, b) => a.checkoutDate.localeCompare(b.checkoutDate) || a.propertyName.localeCompare(b.propertyName));
  }, [properties, propertyBookingEvents, todayYmd]);

  const bookingDirectoryItems = useMemo(() => {
    const propertyById = new Map(properties.map((property) => [property.id, property]));

    return propertyBookingEvents
      .map((event) => {
        const property = propertyById.get(event.property_id) || null;
        const guestCount = Number.isFinite(Number(event.guest_count)) ? Number(event.guest_count) : null;
        const summary = event.summary?.trim() || "";
        const sourceLabel = getBookingSourceLabel(event.source);
        const checkinTime = formatTimeLabel(property?.default_checkin_time);
        const checkoutTime = formatTimeLabel(property?.default_checkout_time);
        const isCurrent = event.checkin_date <= todayYmd && event.checkout_date > todayYmd;
        const isUpcoming = event.checkin_date > todayYmd;
        const status: BookingsFilterStatus = isCurrent ? "current" : isUpcoming ? "upcoming" : "past";

        return {
          id: event.id,
          propertyId: event.property_id,
          propertyName: property?.name || property?.address || "Unknown property",
          sourceLabel,
          summary,
          guestName: summary,
          guestCount,
          adminNote: event.admin_note?.trim() || "",
          adminNoteImportant: Boolean(event.admin_note_important),
          checkinDate: event.checkin_date,
          checkoutDate: event.checkout_date,
          checkinLabel: `${formatDateLabel(event.checkin_date)}${checkinTime ? ` at ${checkinTime}` : ""}`,
          checkoutLabel: `${formatDateLabel(event.checkout_date)}${checkoutTime ? ` at ${checkoutTime}` : ""}`,
          status,
          sortBucket: status === "current" ? 0 : status === "upcoming" ? 1 : 2,
          searchBlob: [
            property?.name || "",
            property?.address || "",
            summary,
            sourceLabel,
            event.external_uid || "",
            event.checkin_date,
            event.checkout_date,
          ]
            .join(" ")
            .toLowerCase(),
        };
      })
      .sort((a, b) => {
        if (a.sortBucket !== b.sortBucket) return a.sortBucket - b.sortBucket;
        if (a.status === "past" && b.status === "past") {
          return b.checkinDate.localeCompare(a.checkinDate) || a.propertyName.localeCompare(b.propertyName);
        }
        return a.checkinDate.localeCompare(b.checkinDate) || a.propertyName.localeCompare(b.propertyName);
      });
  }, [properties, propertyBookingEvents, todayYmd]);

  const filteredBookingDirectoryItems = useMemo(() => {
    const query = bookingsSearchQuery.trim().toLowerCase();

    return bookingDirectoryItems.filter((item) => {
      if (selectedBookingsPropertyFilter !== "all" && item.propertyId !== selectedBookingsPropertyFilter) return false;
      if (bookingsFilterStatus !== "all" && item.status !== bookingsFilterStatus) return false;
      if (query && !item.searchBlob.includes(query)) return false;
      return true;
    });
  }, [bookingDirectoryItems, bookingsFilterStatus, bookingsSearchQuery, selectedBookingsPropertyFilter]);

  const upcomingWastePickups = useMemo(() => {
    const pickups: Array<{
      id: string;
      propertyName: string;
      city: string;
      dateYmd: string;
      dateLabel: string;
      pickupLabel: string;
      notes: string;
    }> = [];

    for (const property of properties) {
      const pickupWeekday =
        typeof property.garbage_pickup_weekday === "number"
          ? property.garbage_pickup_weekday
          : null;

      if (pickupWeekday === null) continue;

      for (const dateYmd of serviceLookaheadYmds) {
        const pickupDate = ymdToLocalDate(dateYmd);
        if (pickupDate.getDay() !== pickupWeekday) continue;

        let pickupLabel = getWastePickupLabel(property.garbage_day) || "Waste pickup";
        const weekALabel = property.garbage_week_a_label?.trim() || "Garbage + recycling";
        const weekBLabel = property.garbage_week_b_label?.trim() || "Recycling only";

        if (property.garbage_rotation_anchor_date) {
          const weeksFromAnchor = Math.floor(diffDays(property.garbage_rotation_anchor_date, dateYmd) / 7);
          const rotationIndex = ((weeksFromAnchor % 2) + 2) % 2;
          pickupLabel = rotationIndex === 0 ? weekALabel : weekBLabel;
        }

        if (isNoWastePickupLabel(pickupLabel)) continue;

        pickups.push({
          id: `${property.id}-${dateYmd}`,
          propertyName: property.name || property.address || "Unknown property",
          city: getCityFromAddress(property.address),
          dateYmd,
          dateLabel:
            dateYmd === todayYmd
              ? "Today"
              : dateYmd === tomorrowYmd
                ? "Tomorrow"
                : formatDateLabel(dateYmd),
          pickupLabel,
          notes: property.garbage_notes?.trim() || "",
        });
      }
    }

    return pickups.sort((a, b) => a.dateYmd.localeCompare(b.dateYmd) || a.propertyName.localeCompare(b.propertyName));
  }, [properties, serviceLookaheadYmds, todayYmd, tomorrowYmd]);

