  function getGroundsJobDisplayStatus(job: GroundsJob, slots: GroundsJobSlot[]) {
    const needed = job.grounds_units_needed || Math.max(slots.length, 1);
    const accepted = slots.filter((slot) => slot.status === "accepted").length;
    const offered = slots.filter((slot) => slot.status === "offered").length;
    const declined = slots.filter((slot) => slot.status === "declined").length;

    if (accepted >= needed) return "Fully staffed";
    if (accepted > 0 && job.grounds_units_required_strict) return "Partially filled";
    if (accepted > 0 && !job.grounds_units_required_strict) return "Ready";
    if (offered > 0) return "Waiting for response";
    if (declined > 0) return "Reoffer needed";
    return job.status || "Open";
  }

  function getJobNotificationLabel(slot: JobSlot | GroundsJobSlot) {
    if (slot.status === "offered") {
      const emailLabel = slot.offer_email_sent_at
        ? `email ${formatDateTime(slot.offer_email_sent_at)}`
        : "email pending";
      const pushLabel = slot.offer_push_sent_at
        ? `push ${formatDateTime(slot.offer_push_sent_at)}`
        : "push pending";
      return `Offer: ${emailLabel} | ${pushLabel}`;
    }

    if (slot.status === "accepted") {
      const emailLabel = slot.day_of_reminder_sent_at
        ? `email ${formatDateTime(slot.day_of_reminder_sent_at)}`
        : "email pending";
      const pushLabel = slot.day_of_reminder_push_sent_at
        ? `push ${formatDateTime(slot.day_of_reminder_push_sent_at)}`
        : "push pending";
      return `Day-of reminder: ${emailLabel} | ${pushLabel}`;
    }

    if (slot.offer_reminder_sent_at || slot.offer_reminder_push_sent_at) {
      const emailLabel = slot.offer_reminder_sent_at
        ? `email ${formatDateTime(slot.offer_reminder_sent_at)}`
        : "email pending";
      const pushLabel = slot.offer_reminder_push_sent_at
        ? `push ${formatDateTime(slot.offer_reminder_push_sent_at)}`
        : "push pending";
      return `Reminder: ${emailLabel} | ${pushLabel}`;
    }
    return "No active notice";
  }

  function toggleSlotNotificationDetails(slotId: string) {
    setExpandedNotificationSlotIds((current) => {
      const next = new Set(current);
      if (next.has(slotId)) {
        next.delete(slotId);
      } else {
        next.add(slotId);
      }
      return next;
    });
  }

  function getSlotNotificationSummary(slot: JobSlot | GroundsJobSlot) {
    const emailSent = Boolean(
      slot.offer_email_sent_at ||
      slot.offer_reminder_sent_at ||
      slot.day_of_reminder_sent_at
    );
    const pushSent = Boolean(
      slot.offer_push_sent_at ||
      slot.offer_reminder_push_sent_at ||
      slot.day_of_reminder_push_sent_at
    );
    return `Email ${emailSent ? "sent" : "pending"} | Push ${pushSent ? "sent" : "pending"} | SMS future`;
  }

  function renderSlotNotificationDetails(slot: JobSlot | GroundsJobSlot) {
    const rows = [
      { label: "Offer email", value: slot.offer_email_sent_at },
      { label: "Offer push", value: slot.offer_push_sent_at },
      { label: "Reminder email", value: slot.offer_reminder_sent_at },
      { label: "Reminder push", value: slot.offer_reminder_push_sent_at },
      { label: "Day-of email", value: slot.day_of_reminder_sent_at },
      { label: "Day-of push", value: slot.day_of_reminder_push_sent_at },
      { label: "SMS", value: null, placeholder: "Coming soon" },
    ];

    return (
      <div className="mt-2 grid gap-1 rounded-[14px] border border-[#eadfce] bg-[#fcfaf7] px-3 py-2 text-[11px] text-[#6f6255] sm:grid-cols-2">
        {rows.map((row) => (
          <div key={row.label} className="flex items-center justify-between gap-2 rounded-full bg-white px-2 py-1">
            <span className="font-medium">{row.label}</span>
            <span className={row.value ? "text-[#236b30]" : "text-[#8a7b68]"}>
              {row.value ? formatDateTime(row.value) : row.placeholder || "Not sent"}
            </span>
          </div>
        ))}
      </div>
    );
  }

  function getJobNotificationTone(slot: JobSlot | GroundsJobSlot) {
    if (slot.status === "offered" && (!slot.offer_email_sent_at || !slot.offer_push_sent_at)) {
      return "border-[#f0b4b4] bg-[#fff5f5] text-[#8a2e22]";
    }

    if (
      slot.offer_email_sent_at ||
      slot.offer_reminder_sent_at ||
      slot.day_of_reminder_sent_at ||
      slot.offer_push_sent_at ||
      slot.offer_reminder_push_sent_at ||
      slot.day_of_reminder_push_sent_at
    ) {
      return "border-[#bbdfc0] bg-[#f0fbf2] text-[#236b30]";
    }

    return "border-[#d8c7ab] bg-white text-[#6f6255]";
  }

