    setInvoiceSettingsDirty(true);
    setInvoiceTaxLines((lines) =>
      lines.length === 1 ? [{ id: "tax-1", label: "Tax", rate: "0", enabled: true }] : lines.filter((line) => line.id !== id)
    );
